  1→import { useState, useEffect, useRef, useCallback } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { Sidebar } from "./features/repos/Sidebar";
  4→import { useReposQuery } from "./hooks/use-tauri-query";
  5→import { TitleBar } from "./components/TitleBar";
  6→import { TabBar } from "./components/TabBar";
  7→import { CheckpointList } from "./features/checkpoints/CheckpointList";
  8→import { TranscriptView } from "./features/transcripts/TranscriptView";
  9→import { DiffView, BranchDiffView } from "./features/diff/DiffView";
 10→import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
 11→import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
 12→import { BranchDebugContainer } from "./features/debug/BranchDebugContainer";
 13→import { CheckpointDebugContainer } from "./features/debug/CheckpointDebugContainer";
 14→import { TerminalPanel } from "./features/terminal/TerminalPanel";
 15→import type { TerminalPanelHandle } from "./features/terminal/TerminalPanel";
 16→import { createBranchTab, createWorktreeTab } from "./features/repos/tab-state";
 17→import { DEFAULT_SIDEBAR_WIDTH, clampSidebarWidth } from "./features/repos/sidebar-width.ts";
 18→import { planWorktreeDeletionCleanup } from "./features/repos/worktree-delete-state.ts";
 19→import {
 20→  collectWorkspaceSurfaceIds,
 21→  createTerminalWorkspace,
 22→  type TerminalWorkspace,
 23→  type WorkspaceUpdate,
 24→} from "./features/terminal/workspace";
 25→import {
 26→  createTerminalPanelVisibility,
 27→  isTerminalPanelOpen,
 28→  setTerminalPanelOpen,
 29→  syncTerminalPanelVisibility,
 30→} from "./features/terminal/panel-visibility";
 31→import {
 32→  DEFAULT_TERMINAL_HEIGHT,
 33→  clampTerminalHeight,
 34→} from "./features/terminal/resize.ts";
 35→import { useLiveUpdates } from "./hooks/use-live-updates";
 36→import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 37→import { ArrowLeft, GitCommit } from "lucide-react";
 38→
 39→export interface Tab {
 40→  id: string;
 41→  branch: string;
 42→  repoPath: string;
 43→  worktree: WorktreeInfo | null;
 44→  kind: "branch" | "agent";
 45→  agent: string | null;
 46→  hasActiveSession: boolean;
 47→}
 48→
 49→function resolveAgent(agent: string) {
 50→  return agent === "codex" ? "codex" : "claude-code";
 51→}
 52→
 53→export default function App() {
 54→  const [tabs, setTabs] = useState<Tab[]>([
 55→    {
 56→      id: "main",
 57→      branch: "main",
 58→      repoPath: "",
 59→      worktree: null,
 60→      kind: "branch",
 61→      agent: null,
 62→      hasActiveSession: false,
 63→    },
 64→  ]);
 65→  const [activeTabId, setActiveTabId] = useState("main");
 66→  const [sidebarWidth, setSidebarWidth] = useState(DEFAULT_SIDEBAR_WIDTH);
 67→  const [terminalHeight, setTerminalHeight] = useState(() => {
 68→    const storedHeight = Number(localStorage.getItem("entire:terminal-height"));
 69→    const initialHeight = Number.isFinite(storedHeight) && storedHeight > 0
 70→      ? storedHeight
 71→      : DEFAULT_TERMINAL_HEIGHT;
 72→
 73→    return clampTerminalHeight(initialHeight, window.innerHeight);
 74→  });
 75→  const [terminalPanelVisibility, setTerminalPanelVisibility] = useState(
 76→    () => createTerminalPanelVisibility(["main"])
 77→  );
 78→  const [innerTab, setInnerTab] = useState<
 79→    "checkpoints" | "diff" | "insights" | "debug"
 80→  >("checkpoints");
 81→  const [selectedCheckpoint, setSelectedCheckpoint] =
 82→    useState<CheckpointSummary | null>(null);
 83→  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 84→    "transcript" | "diff" | "insights" | "debug"
 85→  >("transcript");
 86→
 87→  const [workspaceMap, setWorkspaceMap] = useState<Map<string, TerminalWorkspace>>(
 88→    () => new Map([["main", createTerminalWorkspace()]])
 89→  );
 90→  const [pendingAgentLaunch, setPendingAgentLaunch] = useState<{
 91→    tabId: string;
 92→    agent: string;
 93→    prompt: string;
 94→  } | null>(null);
 95→
 96→  const terminalRef = useRef<TerminalPanelHandle>(null);
 97→
 98→  // Load repos so we can auto-populate the initial tab
 99→  const { data: repos } = useReposQuery();
100→
101→  // Auto-populate the initial tab's repoPath from the first discovered repo
102→  useEffect(() => {
103→    invoke("debug_log", {
104→      message: `useEffect[repos]: repos=${repos ? repos.length : "null"}, first repo path=${repos?.[0]?.path ?? "none"}`,
105→    }).catch(() => {});
106→
107→    if (!repos || repos.length === 0) return;
108→    setTabs((prev) => {
109→      const updated = prev.map((tab) => {
110→        if (tab.id === "main" && !tab.repoPath) {
111→          const repo = repos[0];
112→          const headBranch = repo.branches.find((b: { is_head: boolean }) => b.is_head);
113→          const newPath = repo.path;
114→          const newBranch = headBranch?.name ?? repo.branches[0]?.name ?? "main";
115→          invoke("debug_log", {
116→            message: `Auto-populating initial tab: repoPath=${newPath}, branch=${newBranch}`,
117→          }).catch(() => {});
118→          return {
119→            ...tab,
120→            repoPath: newPath,
121→            branch: newBranch,
122→          };
123→        }
124→        return tab;
125→      });
126→      return updated;
127→    });
128→  }, [repos]);
129→
130→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
131→  const activeWorkspace =
132→    workspaceMap.get(activeTabId) ?? createTerminalWorkspace();
133→  const isTerminalOpen = isTerminalPanelOpen(terminalPanelVisibility, activeTabId);
134→  const tabsWithSessions = tabs.map((tab) => ({
135→    ...tab,
136→    hasActiveSession: collectWorkspaceSurfaceIds(workspaceMap.get(tab.id)).length > 0,
137→  }));
138→
139→  // Live updates — watch active repo for checkpoint/session changes
140→  useLiveUpdates(activeTab.repoPath);
141→
142→  useEffect(() => {
143→    setWorkspaceMap((prev) => {
144→      let changed = false;
145→      const next = new Map(prev);
146→      for (const tab of tabs) {
147→        if (!next.has(tab.id)) {
148→          next.set(tab.id, createTerminalWorkspace());
149→          changed = true;
150→        }
151→      }
152→      return changed ? next : prev;
153→    });
154→  }, [tabs]);
155→
156→  useEffect(() => {
157→    setTerminalPanelVisibility((prev) =>
158→      syncTerminalPanelVisibility(
159→        prev,
160→        tabs.map((tab) => tab.id)
161→      )
162→    );
163→  }, [tabs]);
164→
165→  const handleWorkspaceChange = useCallback(
166→    (tabId: string, update: WorkspaceUpdate) => {
167→      setWorkspaceMap((prev) => {
168→        const next = new Map(prev);
169→        const current = next.get(tabId) ?? createTerminalWorkspace();
170→        next.set(
171→          tabId,
172→          typeof update === "function" ? update(current) : update
173→        );
174→        return next;
175→      });
176→    },
177→    []
178→  );
179→
180→  const handleSetTerminalOpen = useCallback((tabId: string, isOpen: boolean) => {
181→    setTerminalPanelVisibility((prev) => setTerminalPanelOpen(prev, tabId, isOpen));
182→  }, []);
183→
184→  // Terminal dispatch — open shell and optionally send a prompt
185→  const handleSendToAgent = useCallback(
186→    (agent: string, prompt: string) => {
187→      if (!activeTab.repoPath) return;
188→
189→      const resolvedAgent = resolveAgent(agent);
190→      const tabId = `agent:${resolvedAgent}:${Date.now()}`;
191→      const agentTab: Tab = {
192→        id: tabId,
193→        branch: activeTab.branch,
194→        repoPath: activeTab.repoPath,
195→        worktree: activeTab.worktree,
196→        kind: "agent",
197→        agent: resolvedAgent,
198→        hasActiveSession: false,
199→      };
200→
201→      setTabs((prev) => [...prev, agentTab]);
202→      setActiveTabId(tabId);
203→      handleSetTerminalOpen(tabId, true);
204→      setPendingAgentLaunch({ tabId, agent: resolvedAgent, prompt });
205→    },
206→    [activeTab, handleSetTerminalOpen]
207→  );
208→
209→  useEffect(() => {
210→    if (!pendingAgentLaunch) return;
211→    if (pendingAgentLaunch.tabId !== activeTabId) return;
212→    if (!isTerminalOpen) return;
213→
214→    let cancelled = false;
215→    let timer = 0;
216→
217→    const launch = () => {
218→      if (cancelled) return;
219→      if (!terminalRef.current) {
220→        timer = window.setTimeout(launch, 50);
221→        return;
222→      }
223→
224→      terminalRef.current
225→        .launchSession({
226→          agent: pendingAgentLaunch.agent,
227→          prompt: pendingAgentLaunch.prompt,
228→        })
229→        .finally(() => {
230→          setPendingAgentLaunch((current) =>
231→            current?.tabId === pendingAgentLaunch.tabId ? null : current
232→          );
233→        });
234→    };
235→
236→    timer = window.setTimeout(launch, 50);
237→    return () => {
238→      cancelled = true;
239→      window.clearTimeout(timer);
240→    };
241→  }, [activeTabId, isTerminalOpen, pendingAgentLaunch]);
242→
243→  // Persist UI state to localStorage
244→  useEffect(() => {
245→    localStorage.setItem("entire:terminal-height", String(terminalHeight));
246→  }, [terminalHeight]);
247→  useEffect(() => {
248→    function handleWindowResize() {
249→      setTerminalHeight((currentHeight) =>
250→        clampTerminalHeight(currentHeight, window.innerHeight)
251→      );
252→    }
253→
254→    window.addEventListener("resize", handleWindowResize);
255→    return () => window.removeEventListener("resize", handleWindowResize);
256→  }, []);
257→
258→  // Clear selected checkpoint when switching branch tabs
259→  useEffect(() => {
260→    setSelectedCheckpoint(null);
261→    setCheckpointInnerTab("transcript");
262→  }, [activeTabId]);
263→
264→  // Keyboard shortcuts
265→  useEffect(() => {
266→    function onKeyDown(e: KeyboardEvent) {
267→      const meta = e.metaKey || e.ctrlKey;
268→
269→      // Cmd+K = focus search
270→      if (meta && e.key === "k") {
271→        e.preventDefault();
272→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
273→      }
274→      // Ctrl+` = toggle terminal
275→      if (e.ctrlKey && e.key === "`") {
276→        e.preventDefault();
277→        handleSetTerminalOpen(activeTabId, !isTerminalOpen);
278→      }
279→      // Cmd+W = close active tab
280→      if (meta && e.key === "w") {
281→        e.preventDefault();
282→        handleCloseTab(activeTabId);
283→      }
284→      // Cmd+1-9 = switch to tab by index
285→      if (meta && e.key >= "1" && e.key <= "9") {
286→        e.preventDefault();
287→        const idx = parseInt(e.key) - 1;
288→        if (idx < tabs.length) {
289→          setActiveTabId(tabs[idx].id);
290→        }
291→      }
292→      // Cmd+[ / Cmd+] = prev/next tab
293→      if (meta && e.key === "[") {
294→        e.preventDefault();
295→        const idx = tabs.findIndex((t) => t.id === activeTabId);
296→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
297→      }
298→      if (meta && e.key === "]") {
299→        e.preventDefault();
300→        const idx = tabs.findIndex((t) => t.id === activeTabId);
301→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
302→      }
303→      // Escape = deselect checkpoint
304→      if (e.key === "Escape" && selectedCheckpoint) {
305→        setSelectedCheckpoint(null);
306→      }
307→    }
308→    window.addEventListener("keydown", onKeyDown);
309→    return () => window.removeEventListener("keydown", onKeyDown);
310→  }, [activeTabId, handleSetTerminalOpen, isTerminalOpen, tabs, selectedCheckpoint]);
311→
312→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
313→    const newTab = createBranchTab(branch, repoPath);
314→    const existing = tabs.find(
315→      (t) =>
316→        t.kind === "branch" &&
317→        t.branch === newTab.branch &&
318→        t.repoPath === newTab.repoPath
319→    );
320→    if (existing) {
321→      setActiveTabId(existing.id);
322→    } else {
323→      setTabs([...tabs, newTab]);
324→      setActiveTabId(newTab.id);
325→    }
326→  }
327→
328→  function handleWorktreeSelect(wt: WorktreeInfo) {
329→    const newTab = createWorktreeTab(wt);
330→    const existing = tabs.find(
331→      (t) =>
332→        t.kind === "branch" &&
333→        t.branch === newTab.branch &&
334→        t.repoPath === newTab.repoPath
335→    );
336→    if (existing) {
337→      setActiveTabId(existing.id);
338→    } else {
339→      setTabs([...tabs, newTab]);
340→      setActiveTabId(newTab.id);
341→    }
342→  }
343→
344→  function handleCloseTab(tabId: string) {
345→    if (tabs.length <= 1) return;
346→    const idx = tabs.findIndex((t) => t.id === tabId);
347→    const newTabs = tabs.filter((t) => t.id !== tabId);
348→    setTabs(newTabs);
349→    if (activeTabId === tabId) {
350→      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
351→    }
352→    const closedWorkspace = workspaceMap.get(tabId);
353→    for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
354→      invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
355→    }
356→    setWorkspaceMap((prev) => {
357→      const next = new Map(prev);
358→      next.delete(tabId);
359→      return next;
360→    });
361→  }
362→
363→  function handleBranchDeleted(branchName: string, repoPath: string) {
364→    const tabsToRemove = tabs.filter(
365→      (tab) =>
366→        tab.kind === "branch" &&
367→        tab.worktree === null &&
368→        tab.branch === branchName &&
369→        tab.repoPath === repoPath
370→    );
371→
372→    if (tabsToRemove.length === 0) {
373→      return;
374→    }
375→
376→    const nextTabs = tabs.filter((tab) => !tabsToRemove.some((candidate) => candidate.id === tab.id));
377→    setTabs(nextTabs);
378→
379→    if (tabsToRemove.some((tab) => tab.id === activeTabId) && nextTabs.length > 0) {
380→      setActiveTabId(nextTabs[0].id);
381→    }
382→
383→    setWorkspaceMap((prev) => {
384→      const next = new Map(prev);
385→      for (const tab of tabsToRemove) {
386→        const closedWorkspace = next.get(tab.id);
387→        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
388→          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
389→        }
390→        next.delete(tab.id);
391→      }
392→      return next;
393→    });
394→  }
395→
396→  function handleWorktreeDeleted(worktreePath: string) {
397→    const cleanup = planWorktreeDeletionCleanup({
398→      tabs,
399→      activeTabId,
400→      worktreePath,
401→    });
402→
403→    if (cleanup.removedTabIds.length === 0) {
404→      return;
405→    }
406→
407→    setTabs(cleanup.remainingTabs);
408→
409→    if (cleanup.nextActiveTabId && cleanup.nextActiveTabId !== activeTabId) {
410→      setActiveTabId(cleanup.nextActiveTabId);
411→    }
412→
413→    setWorkspaceMap((prev) => {
414→      const next = new Map(prev);
415→      for (const tabId of cleanup.removedTabIds) {
416→        const closedWorkspace = next.get(tabId);
417→        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
418→          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
419→        }
420→        next.delete(tabId);
421→      }
422→      return next;
423→    });
424→  }
425→
426→  function handleResizeStart(e: React.MouseEvent) {
427→    e.preventDefault();
428→    const startY = e.clientY;
429→    const startHeight = terminalHeight;
430→
431→    function onMouseMove(ev: MouseEvent) {
432→      const delta = startY - ev.clientY;
433→      setTerminalHeight(
434→        clampTerminalHeight(startHeight + delta, window.innerHeight)
435→      );
436→    }
437→    function onMouseUp() {
438→      window.removeEventListener("mousemove", onMouseMove);
439→      window.removeEventListener("mouseup", onMouseUp);
440→    }
441→    window.addEventListener("mousemove", onMouseMove);
442→    window.addEventListener("mouseup", onMouseUp);
443→  }
444→
445→  function handleSidebarResizeStart(e: React.MouseEvent<HTMLDivElement>) {
446→    e.preventDefault();
447→    const startX = e.clientX;
448→    const startWidth = sidebarWidth;
449→
450→    function onMouseMove(ev: MouseEvent) {
451→      const delta = ev.clientX - startX;
452→      setSidebarWidth(clampSidebarWidth(startWidth + delta));
453→    }
454→
455→    function onMouseUp() {
456→      window.removeEventListener("mousemove", onMouseMove);
457→      window.removeEventListener("mouseup", onMouseUp);
458→    }
459→
460→    window.addEventListener("mousemove", onMouseMove);
461→    window.addEventListener("mouseup", onMouseUp);
462→  }
463→
464→  const repoName = activeTab.repoPath
465→    ? activeTab.repoPath.split("/").pop()
466→    : "";
467→
468→  return (
469→    <div className="flex h-screen flex-col">
470→      <TitleBar
471→        title={`Entire — ${repoName ? `${repoName}/` : ""}${activeTab?.branch ?? ""}`}
472→      />
473→
474→      <div className="flex flex-1 overflow-hidden">
475→        {/* Sidebar */}
476→        <Sidebar
477→          activeTab={activeTab}
478→          width={sidebarWidth}
479→          onBranchSelect={handleBranchSelect}
480→          onBranchDeleted={handleBranchDeleted}
481→          onWorktreeDeleted={handleWorktreeDeleted}
482→          onWorktreeSelect={handleWorktreeSelect}
483→          onResizeStart={handleSidebarResizeStart}
484→        />
485→
486→        {/* Main content */}
487→        <div className="flex flex-1 flex-col overflow-hidden">
488→          <TabBar
489→            tabs={tabsWithSessions}
490→            activeTabId={activeTabId}
491→            onSelectTab={setActiveTabId}
492→            onCloseTab={handleCloseTab}
493→          />
494→
495→          <div className="flex flex-1 flex-col overflow-hidden">
496→            {/* Inner tabs */}
497→            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
498→              {(["checkpoints", "diff", "insights", "debug"] as const).map((tab) => (
499→                <button
500→                  key={tab}
501→                  onClick={() => setInnerTab(tab)}
502→                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
503→                    innerTab === tab
504→                      ? "border-accent text-fg"
505→                      : "border-transparent text-fg-subtle hover:text-fg-muted"
506→                  }`}
507→                >
508→                  {tab === "checkpoints"
509→                    ? "Checkpoints"
510→                    : tab === "diff"
511→                      ? "Diff"
512→                      : tab === "insights"
513→                        ? "Insights"
514→                        : "Debug"}
515→                </button>
516→              ))}
517→            </div>
518→
519→            {/* Main view */}
520→            <div className="flex flex-1 overflow-hidden bg-bg">
521→              {innerTab === "checkpoints" && (
522→                <>
523→                  {/* Checkpoint list — always visible when on checkpoints tab */}
524→                  <div
525→                    className={`overflow-y-auto ${
526→                      selectedCheckpoint
527→                        ? "w-[320px] shrink-0 border-r border-border-subtle"
528→                        : "flex-1"
529→                    }`}
530→                  >
531→                    <CheckpointList
532→                      repoPath={activeTab.repoPath}
533→                      branch={activeTab.branch}
534→                      onSelectCheckpoint={(cp) => {
535→                        setSelectedCheckpoint(cp);
536→                        setCheckpointInnerTab("transcript");
537→                      }}
538→                    />
539→                  </div>
540→
541→                  {/* Checkpoint detail panel */}
542→                  {selectedCheckpoint && (
543→                    <div className="flex flex-1 flex-col overflow-hidden">
544→                      {/* Detail header */}
545→                      <div className="flex items-center gap-3 border-b border-border-subtle px-4 py-2.5">
546→                        <button
547→                          onClick={() => setSelectedCheckpoint(null)}
548→                          className="flex items-center gap-1.5 text-xs text-fg-subtle transition-colors hover:text-fg"
549→                        >
550→                          <ArrowLeft size={14} />
551→                        </button>
552→                        <GitCommit size={14} className="text-fg-subtle" />
553→                        <span className="font-mono text-xs text-accent-fg">
554→                          {selectedCheckpoint.commit_sha
555→                            ? selectedCheckpoint.commit_sha.slice(0, 7)
556→                            : selectedCheckpoint.checkpoint_id.slice(0, 7)}
557→                        </span>
558→                        <span className="truncate text-xs text-fg-muted">
559→                          {selectedCheckpoint.commit_message || "Untitled"}
560→                        </span>
561→                      </div>
562→
563→                      {/* Checkpoint sub-tabs */}
564→                      <div className="flex gap-0 border-b border-border-subtle bg-bg px-4 pt-2">
565→                        {(["transcript", "diff", "insights", "debug"] as const).map(
566→                          (tab) => (
567→                            <button
568→                              key={tab}
569→                              onClick={() => setCheckpointInnerTab(tab)}
570→                              className={`border-b-2 px-3 pb-1.5 text-[11px] font-medium capitalize transition-colors ${
571→                                checkpointInnerTab === tab
572→                                  ? "border-accent text-fg"
573→                                  : "border-transparent text-fg-subtle hover:text-fg-muted"
574→                              }`}
575→                            >
576→                              {tab === "transcript"
577→                                ? "Transcript"
578→                                : tab === "diff"
579→                                  ? "Diff"
580→                                  : tab === "insights"
581→                                    ? "Insights"
582→                                    : "Debug"}
583→                            </button>
584→                          )
585→                        )}
586→                      </div>
587→
588→                      {/* Checkpoint detail content */}
589→                      <div className="flex-1 overflow-y-auto">
590→                        {checkpointInnerTab === "transcript" && (
591→                          <TranscriptView
592→                            repoPath={activeTab.repoPath}
593→                            checkpoint={selectedCheckpoint}
594→                          />
595→                        )}
596→                        {checkpointInnerTab === "diff" && (
597→                          <DiffView
598→                            repoPath={activeTab.repoPath}
599→                            checkpoint={selectedCheckpoint}
600→                            onSendToAgent={handleSendToAgent}
601→                          />
602→                        )}
603→                        {checkpointInnerTab === "insights" && (
604→                          <CheckpointInsightsContainer
605→                            repoPath={activeTab.repoPath}
606→                            checkpoint={selectedCheckpoint}
607→                          />
608→                        )}
609→                        {checkpointInnerTab === "debug" && (
610→                          <CheckpointDebugContainer
611→                            repoPath={activeTab.repoPath}
612→                            checkpoint={selectedCheckpoint}
613→                          />
614→                        )}
615→                      </div>
616→                    </div>
617→                  )}
618→                </>
619→              )}
620→              {innerTab === "diff" && (
621→                <div className="flex flex-1 overflow-hidden">
622→                  <BranchDiffView
623→                    repoPath={activeTab.repoPath}
624→                    branch={activeTab.branch}
625→                    onSendToAgent={handleSendToAgent}
626→                  />
627→                </div>
628→              )}
629→              {innerTab === "insights" && (
630→                <div className="flex flex-1 overflow-y-auto">
631→                  <BranchInsightsContainer
632→                    repoPath={activeTab.repoPath}
633→                    branch={activeTab.branch}
634→                  />
635→                </div>
636→              )}
637→              {innerTab === "debug" && (
638→                <div className="flex flex-1 overflow-y-auto">
639→                  <BranchDebugContainer
640→                    repoPath={activeTab.repoPath}
641→                    branch={activeTab.branch}
642→                  />
643→                </div>
644→              )}
