 76→pub fn register_repo(path: &str) -> Result<(), String> {
 77→    let p = Path::new(path);
 78→
 79→    if !p.is_dir() {
 80→        return Err("Path is not a directory".to_string());
 81→    }
 82→
 83→    // Validate it's a git repo
 84→    git2::Repository::open(p).map_err(|_| "Not a git repository".to_string())?;
 85→
 86→    // Validate .entire is enabled
 87→    if !is_entire_enabled(path) {
 88→        return Err("Repository does not have Entire enabled (.entire/settings.json with enabled: true)".to_string());
 89→    }
 90→
 91→    // Canonicalize to avoid duplicates from different path representations
 92→    let canonical = p
 93→        .canonicalize()
 94→        .map_err(|e| format!("Failed to resolve path: {}", e))?
 95→        .to_string_lossy()
 96→        .to_string();
 97→
 98→    let mut repos = load_registered_repos();
 99→    if repos.contains(&canonical) {
100→        return Ok(()); // Already registered, not an error
101→    }
102→
103→    repos.push(canonical);
104→    save_registered_repos(&repos)
105→}
106→
107→pub fn unregister_repo(path: &str) -> Result<(), String> {
108→    let mut repos = load_registered_repos();
109→    let canonical = Path::new(path)
110→        .canonicalize()
111→        .map(|p| p.to_string_lossy().to_string())
112→        .unwrap_or_else(|_| path.to_string());
113→
114→    repos.retain(|r| r != &canonical && r != path);
115→    save_registered_repos(&repos)
116→}
117→
118→pub fn get_registered_repos() -> Vec<String> {
119→    load_registered_repos()
120→}
121→
122→/// Discover repos with Entire enabled by scanning common directories
123→pub fn discover_repos() -> Vec<String> {
124→    let mut seen = HashSet::new();
125→    let mut repos = Vec::new();
126→    let home = dirs_next().unwrap_or_default();
127→
128→    // Scan common project directories
129→    let scan_dirs = vec![
130→        PathBuf::from(&home).join("Projects"),
131→        PathBuf::from(&home).join("code"),
132→        PathBuf::from(&home).join("src"),
133→        PathBuf::from(&home).join("dev"),
134→    ];
135→
136→    for dir in scan_dirs {
137→        if dir.exists() {
138→            if let Ok(entries) = fs::read_dir(&dir) {
139→                for entry in entries.flatten() {
140→                    let path = entry.path();
141→                    if path.is_dir() && is_entire_enabled(&path.to_string_lossy()) {
142→                        let s = path.to_string_lossy().to_string();
143→                        if seen.insert(s.clone()) {
144→                            repos.push(s);
145→                        }
146→                    }
147→                }
148→            }
149→        }
150→    }
151→
152→    // Merge in manually registered repos
153→    for registered in load_registered_repos() {
154→        if seen.insert(registered.clone()) {
155→            // Only add if the repo still exists and is still enabled
156→            if Path::new(&registered).is_dir() && is_entire_enabled(&registered) {
157→                repos.push(registered);
158→            }
159→        }
160→    }
161→
162→    repos
163→}
164→
165→fn dirs_next() -> Option<String> {
166→    std::env::var("HOME").ok()
167→}
