#[tauri::command]
fn get_entire_logs(repo_path: String, tail_lines: u32) -> Result<EntireLogResult, String> {
    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
    if !log_path.exists() {
        return Err("No log file found".to_string());
