export const TerminalPanel = forwardRef<TerminalPanelHandle, TerminalPanelProps>(
  function TerminalPanel({ height, tab, workspace, onWorkspaceChange, onToggle, dialogOpen }, ref) {
  const [isLaunching, setIsLaunching] = useState(false);
  const [isDropTarget, setIsDropTarget] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const panelRef = useRef<HTMLDivElement>(null);
  const activeTerminalTab = getActiveTerminalTab(workspace);
  const activePane =
    activeTerminalTab?.panes.find((pane) => pane.id === activeTerminalTab.activePaneId) ??
    activeTerminalTab?.panes[0] ??
    null;
  const activeSurfaceId = activePane?.session?.id ?? null;

  const isPositionInsidePanel = useCallback((position: { x: number; y: number }) => {
    const rect = panelRef.current?.getBoundingClientRect();
    if (!rect) return false;

    return (
      position.x >= rect.left &&
      position.x <= rect.right &&
      position.y >= rect.top &&
      position.y <= rect.bottom
    );
  }, []);

  const sendDroppedImagePaths = useCallback(async (paths: string[]) => {
    if (!activeSurfaceId) return;

    const text = formatDroppedImagePaths(paths);
    if (!text) return;

    try {
      await invoke("ghostty_send_text", {
        surfaceId: activeSurfaceId,
        text,
      });
      await invoke("ghostty_focus_overlay", { surfaceId: activeSurfaceId });
    } catch (err) {
      console.error("Failed to send dropped paths to terminal:", err);
      setError("Could not insert dropped image path into the terminal");
    }
  }, [activeSurfaceId]);

  const focusPane = useCallback(
    (terminalTabId: string, paneId: string) => {
      const nextWorkspace = setActivePaneInTerminalTab(
        setActiveTerminalTabInWorkspace(workspace, terminalTabId),
        terminalTabId,
        paneId
      );
      onWorkspaceChange(nextWorkspace);
      const pane = nextWorkspace.terminalTabs
        .find((terminalTab) => terminalTab.id === terminalTabId)
        ?.panes.find((candidate) => candidate.id === paneId);
      if (pane?.session) {
        invoke("ghostty_focus_overlay", { surfaceId: pane.session.id }).catch(
          console.error
        );
      }
    },
    [workspace, onWorkspaceChange]
  );

  const launchTerminal = useCallback(
    async (
      agent = "terminal",
      target?: { terminalTabId?: string; paneId?: string }
    ) => {
      debugLog(`launchTerminal called: tab.id=${tab.id}, tab.repoPath=${JSON.stringify(tab.repoPath)}, tab.branch=${tab.branch}, isLaunching=${isLaunching}`);

      if (!tab.repoPath) {
        debugLog("BAIL: tab.repoPath is empty/falsy");
        setError("No repository selected — pick a branch from the sidebar");
        return "";
      }
      if (isLaunching) {
        debugLog("BAIL: isLaunching=true, already in progress");
        return "";
      }

      let nextWorkspace = workspace;
      let terminalTabId = target?.terminalTabId;
      let paneId = target?.paneId;

      if (!terminalTabId || !paneId) {
        const launchTarget = resolveAgentLaunchTarget(nextWorkspace);
        if (launchTarget.mode === "create-terminal-tab") {
          nextWorkspace = createTerminalTabInWorkspace(nextWorkspace);
          const nextTarget = resolveAgentLaunchTarget(nextWorkspace);
          if (nextTarget.mode === "create-terminal-tab") {
            return "";
          }
          terminalTabId = nextTarget.terminalTabId;
          paneId = nextTarget.paneId;
        } else {
          terminalTabId = launchTarget.terminalTabId;
          paneId = launchTarget.paneId;
        }
      }

      if (!terminalTabId || !paneId) {
        return "";
      }

      nextWorkspace = setActivePaneInTerminalTab(
        setActiveTerminalTabInWorkspace(nextWorkspace, terminalTabId),
        terminalTabId,
        paneId
      );
      onWorkspaceChange(nextWorkspace);

      const targetTab = nextWorkspace.terminalTabs.find(
        (terminalTab) => terminalTab.id === terminalTabId
      );
      const targetPane = targetTab?.panes.find((pane) => pane.id === paneId);

      if (targetPane?.session) {
        debugLog(`Reusing existing session ${targetPane.session.id} for pane ${paneId}`);
        return targetPane.session.id;
      }

      setError(null);
      setIsLaunching(true);
      debugLog(`Calling ghostty_create_surface with workingDir=${tab.repoPath}`);
      try {
        const surfaceId: string = await invoke("ghostty_create_surface", {
          workingDir: tab.repoPath,
          command: agent === "terminal" ? undefined : agent,
        });

        debugLog(`ghostty_create_surface returned surfaceId=${surfaceId}`);
        const newSession: TermSession = {
          id: surfaceId,
          agent,
          label: buildSessionLabel(tab.branch, agent),
        };
        onWorkspaceChange((currentWorkspace) =>
          setPaneSession(currentWorkspace, terminalTabId, paneId, newSession)
        );
        return surfaceId;
      } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        debugLog(`ghostty_create_surface FAILED: ${message}`);
        console.error("Failed to create ghostty surface:", err);
        setError(`Terminal failed: ${message}`);
        return "";
      } finally {
        setIsLaunching(false);
      }
    },
    [tab.id, tab.repoPath, tab.branch, workspace, isLaunching, onWorkspaceChange]
  );

  const killPaneSession = useCallback(async (terminalTabId: string, paneId: string) => {
    const terminalTab = workspace.terminalTabs.find(
      (candidate) => candidate.id === terminalTabId
    );
    const pane = terminalTab?.panes.find((candidate) => candidate.id === paneId);
    if (!pane?.session) return;
    try {
      await invoke("ghostty_destroy_surface", { surfaceId: pane.session.id });
    } catch (err) {
      console.error("Failed to destroy surface:", err);
    }
    onWorkspaceChange((currentWorkspace) =>
      setPaneSession(currentWorkspace, terminalTabId, paneId, null)
    );
  }, [workspace, onWorkspaceChange]);

  const closePane = useCallback(async () => {
    if (!activeTerminalTab || !activePane || activeTerminalTab.panes.length < 2) return;
    await killPaneSession(activeTerminalTab.id, activePane.id);
    onWorkspaceChange((currentWorkspace) =>
      closePaneInTerminalTab(currentWorkspace, activeTerminalTab.id, activePane.id)
    );
  }, [activeTerminalTab, activePane, killPaneSession, onWorkspaceChange]);

  const closeTerminalTab = useCallback(async (terminalTabId: string) => {
    const terminalTab = workspace.terminalTabs.find(
      (candidate) => candidate.id === terminalTabId
    );
    if (!terminalTab) return;

    for (const pane of terminalTab.panes) {
      if (pane.session) {
        try {
          await invoke("ghostty_destroy_surface", { surfaceId: pane.session.id });
        } catch (err) {
          console.error("Failed to destroy surface:", err);
        }
      }
    }

    onWorkspaceChange((currentWorkspace) =>
      closeTerminalTabInWorkspace(currentWorkspace, terminalTabId)
    );
  }, [workspace, onWorkspaceChange]);

  useImperativeHandle(ref, () => ({
    async launchSession(options = {}) {
      const agent = options.agent ?? "terminal";
      const surfaceId = await launchTerminal(agent);
      if (!surfaceId) return;
      if (!options.prompt) return;

      // Small delay for PTY initialization, then send the prompt
      setTimeout(async () => {
        try {
          await invoke("ghostty_send_text", {
            surfaceId,
            text: options.prompt + "\n",
          });
        } catch (err) {
          console.error("Failed to send prompt to terminal:", err);
        }
      }, 300);
    },
  }), [launchTerminal]);

  useEffect(() => {
    if (!tab.repoPath || isLaunching) return;

    const target = resolveAutoLaunchTarget(workspace);
    if (!target?.terminalTabId) return;

    onWorkspaceChange((currentWorkspace) =>
      clearPaneAutoLaunch(currentWorkspace, target.terminalTabId!, target.paneId)
    );
    void launchTerminal("terminal", target);
  }, [tab.repoPath, workspace, isLaunching, launchTerminal, onWorkspaceChange]);

  useEffect(() => {
    let cancelled = false;
    let unlisten: (() => void) | undefined;

    getCurrentWindow()
      .onDragDropEvent((event) => {
        if (cancelled) return;

        if (event.payload.type === "leave") {
          setIsDropTarget(false);
          return;
        }

        const isInside = isPositionInsidePanel(event.payload.position);
        if (event.payload.type === "enter" || event.payload.type === "over") {
          setIsDropTarget(isInside);
          return;
        }

        setIsDropTarget(false);
        if (!isInside) return;
        void sendDroppedImagePaths(event.payload.paths);
      })
      .then((cleanup) => {
        if (cancelled) {
          cleanup();
          return;
        }
        unlisten = cleanup;
      })
      .catch(console.error);

    return () => {
      cancelled = true;
      setIsDropTarget(false);
      unlisten?.();
    };
  }, [isPositionInsidePanel, sendDroppedImagePaths]);

  return (
    <div
      ref={panelRef}
      className="relative flex shrink-0 flex-col bg-[#0a0a0a]"
      style={{ height }}
    >
      <div className="flex items-center gap-2 border-t border-border bg-bg-raised px-3 py-1.5">
        <div className="flex min-w-0 flex-1 items-center gap-1 overflow-x-auto">
          {workspace.terminalTabs.map((terminalTab) => {
            const isActive = terminalTab.id === activeTerminalTab?.id;
            return (
              <div
                key={terminalTab.id}
                className={`flex items-center rounded-md border ${
                  isActive
                    ? "border-accent bg-accent-bg/40 text-accent-fg"
                    : "border-border-subtle text-fg-subtle"
                }`}
              >
                <button
                  onClick={() =>
                    onWorkspaceChange(
                      setActiveTerminalTabInWorkspace(workspace, terminalTab.id)
                    )
                  }
                  className="px-2.5 py-1 text-[11px]"
                >
                  {terminalTab.title}
                </button>
                <button
                  onClick={() => void closeTerminalTab(terminalTab.id)}
                  className="px-2 py-1 text-[11px] hover:text-red"
                  title="Close terminal tab"
                >
                  ✕
                </button>
              </div>
            );
          })}
          <button
            onClick={() => onWorkspaceChange(createTerminalTabInWorkspace(workspace))}
            className="rounded-md border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-accent-fg"
          >
            + Tab
          </button>
        </div>

        <button
          onClick={() =>
            activeTerminalTab &&
            onWorkspaceChange(
              splitActivePaneInTerminalTab(workspace, activeTerminalTab.id, "vertical")
            )
          }
          disabled={!activeTerminalTab || activeTerminalTab.panes.length > 1}
          className="rounded-md border border-border-subtle px-2 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-accent-fg disabled:opacity-50"
        >
          Split Vert
        </button>
        <button
          onClick={() =>
            activeTerminalTab &&
            onWorkspaceChange(
              splitActivePaneInTerminalTab(workspace, activeTerminalTab.id, "horizontal")
            )
          }
          disabled={!activeTerminalTab || activeTerminalTab.panes.length > 1}
          className="rounded-md border border-border-subtle px-2 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-accent-fg disabled:opacity-50"
        >
          Split Horiz
        </button>
        <button
          onClick={onToggle}
          className="ml-auto px-2 py-1 text-[11px] text-fg-subtle hover:text-fg-muted"
        >
          ⌃` Toggle ▾
        </button>
      </div>

      {error && (
        <div className="border-t border-border-subtle px-3 py-1 text-[11px] text-red">
          {error}
        </div>
      )}

      <div className="flex-1 overflow-hidden">
        {activeTerminalTab ? (
          <div
            className={`flex h-full ${
              activeTerminalTab.splitDirection === "horizontal"
                ? "flex-col"
                : "flex-row"
            }`}
          >
            {activeTerminalTab.panes.map((pane, paneIndex) => {
              const isActive = pane.id === activeTerminalTab.activePaneId;
              const paneChrome = getPaneChrome(isActive);
              const paneMeta = pane.session
                ? isActive
                  ? "Live"
                  : "Attached"
                : pane.shouldAutoLaunch
                  ? "Starting"
                  : "Idle";
              const isSplit = activeTerminalTab.panes.length > 1;
              const paneFlexBasis = isSplit
                ? paneIndex === 0
                  ? `${activeTerminalTab.splitRatio * 100}%`
                  : `${(1 - activeTerminalTab.splitRatio) * 100}%`
                : undefined;
              return (
                <React.Fragment key={pane.id}>
                  {paneIndex === 1 && isSplit && (
                    <div
                      onMouseDown={(e) => {
                        e.preventDefault();
                        const isHorizontal = activeTerminalTab.splitDirection === "horizontal";
                        const container = e.currentTarget.parentElement;
                        if (!container) return;
                        const rect = container.getBoundingClientRect();

                        function onMouseMove(ev: MouseEvent) {
                          const ratio = isHorizontal
                            ? (ev.clientY - rect.top) / rect.height
                            : (ev.clientX - rect.left) / rect.width;
                          onWorkspaceChange((currentWorkspace) =>
                            setSplitRatioInTerminalTab(currentWorkspace, activeTerminalTab.id, ratio)
                          );
                        }
                        function onMouseUp() {
                          window.removeEventListener("mousemove", onMouseMove);
                          window.removeEventListener("mouseup", onMouseUp);
                        }
                        window.addEventListener("mousemove", onMouseMove);
                        window.addEventListener("mouseup", onMouseUp);
                      }}
                      className={`shrink-0 bg-border transition-colors hover:bg-accent ${
                        activeTerminalTab.splitDirection === "horizontal"
                          ? "h-[3px] cursor-row-resize"
                          : "w-[3px] cursor-col-resize"
                      }`}
                    />
                  )}
                  <div
                    onClick={() => focusPane(activeTerminalTab.id, pane.id)}
                    className={`flex min-h-0 min-w-0 flex-col ${
                      isActive ? "bg-bg-selected/30" : "bg-transparent"
                    }`}
                    style={isSplit ? { flexBasis: paneFlexBasis, flexGrow: 0, flexShrink: 0 } : { flex: 1 }}
                  >
                    <div className={paneChrome.rowClassName}>
                      <div className={paneChrome.buttonClassName}>
                        <span className={paneChrome.dotClassName} />
                        <span className={paneChrome.titleClassName}>
                          {pane.session?.label ?? "Terminal"}
                        </span>
                        <span className={paneChrome.metaClassName}>{paneMeta}</span>
                      </div>
                      {pane.session ? (
                        <button
                          onClick={(event) => {
                            event.stopPropagation();
                            void (async () => {
                              await killPaneSession(activeTerminalTab.id, pane.id);
                              if (activeTerminalTab.panes.length > 1) {
                                onWorkspaceChange((currentWorkspace) =>
                                  closePaneInTerminalTab(currentWorkspace, activeTerminalTab.id, pane.id)
                                );
                              } else {
                                onToggle();
                              }
                            })();
                          }}
                          className={paneChrome.closeClassName}
                          title="Kill session and close"
                        >
                          ✕
                        </button>
                      ) : (
                        <span className={paneChrome.metaClassName}>
                          {pane.shouldAutoLaunch ? "Starting terminal..." : "Terminal ready"}
                        </span>
                      )}
                    </div>
                    <div className="flex-1 overflow-hidden">
                      <GhosttyTerminal surfaceId={pane.session?.id ?? null} dialogOpen={dialogOpen} />
                    </div>
                  </div>
                </React.Fragment>
              );
            })}
          </div>
        ) : null}
      </div>

      {isDropTarget && (
        <div className="pointer-events-none absolute inset-0 z-20 flex items-center justify-center border-2 border-dashed border-accent bg-accent-bg/55 px-4 text-center text-sm font-medium text-fg backdrop-blur-sm">
          Drop images to insert their file paths into the active terminal
        </div>
      )}
    </div>
  );
});

