export function deriveSuggestedWorktreePath(
  repoPath: string,
  branchName: string,
  basePath?: string | null
): string {
  if (basePath) {
    const repoName = repoPath.split("/").pop() ?? "repo";
    return `${basePath}/${repoName}-${sanitizeBranchSegment(branchName)}`;
  }
  return `${repoPath}-${sanitizeBranchSegment(branchName)}`;
}

