import { useState, useEffect, type FormEvent } from "react";
import {
  GitBranch,
  BookOpen,
  ChevronRight,
  ChevronDown,
  FolderGit2,
  FolderPlus,
  Loader2,
  PanelLeftClose,
  PanelLeftOpen,
  Plus,
  RefreshCw,
  Settings,
  Trash2,
  X,
} from "lucide-react";
import { open } from "@tauri-apps/plugin-dialog";
import type { Tab } from "../../App";
import type { BranchInfo, RepoInfo, WorktreeInfo } from "../../lib/ipc";
import {
  useBlockRepoMutation,
  useCreateWorktreeMutation,
  useDeleteBranchMutation,
  useDeleteWorktreeMutation,
  useRegisterRepoMutation,
  useReposQuery,
  useUnregisterRepoMutation,
} from "../../hooks/use-tauri-query";
import { canDeletePlainBranch } from "./branch-delete-state.ts";
import { buildCreateWorktreeDraft } from "./worktree-dialog-state.ts";
import { isRepoRefreshing } from "./refresh-state";
import { deriveSuggestedWorktreePath } from "./worktree-paths.ts";

interface SidebarProps {
  activeTab: Tab;
  width: number;
  onBranchSelect: (branch: BranchInfo, repoPath: string) => void;
  onBranchDeleted: (branchName: string, repoPath: string) => void;
  onWorktreeDeleted: (worktreePath: string) => void;
  onWorktreeSelect: (wt: WorktreeInfo) => void;
  onResizeStart: (event: React.MouseEvent<HTMLDivElement>) => void;
  onDialogOpen?: (open: boolean) => void;
  onOpenSettings?: () => void;
}

interface CreateWorktreeDialogState {
  repoPath: string;
  mode: "existing" | "new";
  branchName: string;
  targetPath: string;
  pathEdited: boolean;
  error: string | null;
}

interface DeleteWorktreeDialogState {
  repoPath: string;
  worktree: WorktreeInfo;
  error: string | null;
  forceAvailable: boolean;
}

interface DeleteBranchDialogState {
  repoPath: string;
  branchName: string;
  error: string | null;
}

function getErrorMessage(error: unknown): string {
  return error instanceof Error ? error.message : String(error);
}

function getAvailableExistingBranches(repo: RepoInfo): string[] {
  const worktreeBranches = new Set(repo.worktrees.map((worktree) => worktree.branch));
  return repo.branches
    .filter((branch) => !branch.is_head && !worktreeBranches.has(branch.name))
    .map((branch) => branch.name);
}

export function Sidebar({
  activeTab,
  width,
  onBranchSelect,
  onBranchDeleted,
  onWorktreeDeleted,
  onWorktreeSelect,
  onResizeStart,
  onDialogOpen,
  onOpenSettings,
}: SidebarProps) {
  const { data: realRepos, isLoading, error, refetch } = useReposQuery();
  const registerMutation = useRegisterRepoMutation();
  const unregisterMutation = useUnregisterRepoMutation();
  const blockRepoMutation = useBlockRepoMutation();
  const createWorktreeMutation = useCreateWorktreeMutation();
  const deleteBranchMutation = useDeleteBranchMutation();
  const deleteWorktreeMutation = useDeleteWorktreeMutation();

  const repos = realRepos ?? [];

  const [expandedRepos, setExpandedRepos] = useState<Set<string>>(new Set());
  const [repoListCollapsed, setRepoListCollapsed] = useState(false);
  const [collapsed, setCollapsed] = useState(false);
  const [sidebarError, setSidebarError] = useState<string | null>(null);
  const [refreshingRepoPath, setRefreshingRepoPath] = useState<string | null>(null);
  const [createDialog, setCreateDialog] = useState<CreateWorktreeDialogState | null>(null);
  const [deleteBranchDialog, setDeleteBranchDialog] = useState<DeleteBranchDialogState | null>(null);
  const [deleteDialog, setDeleteDialog] = useState<DeleteWorktreeDialogState | null>(null);

  const isAnyDialogOpen = !!(createDialog || deleteDialog || deleteBranchDialog);
  useEffect(() => {
    onDialogOpen?.(isAnyDialogOpen);
  }, [isAnyDialogOpen, onDialogOpen]);

  const createRepo = createDialog
    ? repos.find((repo) => repo.path === createDialog.repoPath) ?? null
    : null;
  const createAvailableBranches = createRepo ? getAvailableExistingBranches(createRepo) : [];
  const worktreeBranches = new Set(
    repos.flatMap((repo) => repo.worktrees.map((worktree) => worktree.branch))
  );

  async function handleAddRepo() {
    setSidebarError(null);
    const selected = await open({ directory: true, multiple: false });
    if (!selected) return;
    registerMutation.mutate(selected, {
      onError: (mutationError) => {
        setSidebarError(getErrorMessage(mutationError));
      },
    });
  }

  async function handleRefreshRepo(repoPath: string) {
    setSidebarError(null);
    setRefreshingRepoPath(repoPath);

    try {
      const result = await refetch();
      if (result.error) {
        setSidebarError(getErrorMessage(result.error));
      }
    } catch (refreshError) {
      setSidebarError(getErrorMessage(refreshError));
    } finally {
      setRefreshingRepoPath(null);
    }
  }

  function handleOpenCreateDialog(repo: RepoInfo) {
    const draft = buildCreateWorktreeDraft(repo);
    setSidebarError(null);
    setCreateDialog({
      repoPath: repo.path,
      mode: draft.mode,
      branchName: draft.branchName,
      targetPath: draft.targetPath,
      pathEdited: false,
      error: null,
    });
  }

  function updateCreateDialog(
    updater: (current: CreateWorktreeDialogState) => CreateWorktreeDialogState
  ) {
    setCreateDialog((current) => (current ? updater(current) : current));
  }

  function handleCreateModeChange(mode: "existing" | "new") {
    updateCreateDialog((current) => {
      if (!createRepo) return current;
      const nextBranchName =
        mode === "existing"
          ? createAvailableBranches[0] ?? ""
          : current.mode === "new"
            ? current.branchName
            : "";
      const nextTargetPath = current.pathEdited
        ? current.targetPath
        : deriveSuggestedWorktreePath(createRepo.path, nextBranchName);

      return {
        ...current,
        mode,
        branchName: nextBranchName,
        targetPath: nextTargetPath,
        error: null,
      };
    });
  }

  function handleCreateBranchNameChange(branchName: string) {
    updateCreateDialog((current) => ({
      ...current,
      branchName,
      targetPath: current.pathEdited
        ? current.targetPath
        : deriveSuggestedWorktreePath(current.repoPath, branchName),
      error: null,
    }));
  }

  async function handleCreateSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    if (!createDialog) return;

    setSidebarError(null);
    updateCreateDialog((current) => ({ ...current, error: null }));

    try {
      await createWorktreeMutation.mutateAsync({
        repoPath: createDialog.repoPath,
        options: {
          mode: createDialog.mode,
          branchName: createDialog.branchName,
          targetPath: createDialog.targetPath,
        },
      });
      setCreateDialog(null);
    } catch (mutationError) {
      const message = getErrorMessage(mutationError);
      setSidebarError(message);
      updateCreateDialog((current) => ({ ...current, error: message }));
    }
  }

  function handleOpenDeleteDialog(repoPath: string, worktree: WorktreeInfo) {
    setSidebarError(null);
    setDeleteDialog({
      repoPath,
      worktree,
      error: null,
      forceAvailable: false,
    });
  }

  function handleOpenDeleteBranchDialog(repoPath: string, branchName: string) {
    setSidebarError(null);
    setDeleteBranchDialog({
      repoPath,
      branchName,
      error: null,
    });
  }

  async function handleDeleteBranchSubmit() {
    if (!deleteBranchDialog) return;

    setSidebarError(null);
    setDeleteBranchDialog((current) => (current ? { ...current, error: null } : current));

    try {
      await deleteBranchMutation.mutateAsync({
        repoPath: deleteBranchDialog.repoPath,
        branchName: deleteBranchDialog.branchName,
      });
      onBranchDeleted(deleteBranchDialog.branchName, deleteBranchDialog.repoPath);
      setDeleteBranchDialog(null);
    } catch (mutationError) {
      const message = getErrorMessage(mutationError);
      setSidebarError(message);
      setDeleteBranchDialog((current) =>
        current ? { ...current, error: message } : current
      );
    }
  }

  async function handleDeleteSubmit(force: boolean) {
    if (!deleteDialog) return;

    setSidebarError(null);
    setDeleteDialog((current) => (current ? { ...current, error: null } : current));

    try {
      await deleteWorktreeMutation.mutateAsync({
        repoPath: deleteDialog.repoPath,
        options: {
          worktreePath: deleteDialog.worktree.path,
          branchName: deleteDialog.worktree.branch,
          force,
        },
      });
      onWorktreeDeleted(deleteDialog.worktree.path);
      setDeleteDialog(null);
    } catch (mutationError) {
      const message = getErrorMessage(mutationError);
      setSidebarError(message);
      setDeleteDialog((current) =>
        current
          ? {
              ...current,
              error: message,
              forceAvailable: current.forceAvailable || !force,
            }
          : current
      );
    }
  }

  useEffect(() => {
    setExpandedRepos(new Set(repos.map((repo) => repo.path)));
  }, [repos]);

  function toggleRepo(path: string) {
    setExpandedRepos((prev) => {
      const next = new Set(prev);
      if (next.has(path)) next.delete(path);
      else next.add(path);
      return next;
    });
  }

  const createSubmitDisabled =
    createWorktreeMutation.isPending ||
    !createDialog ||
    !createDialog.branchName.trim() ||
    !createDialog.targetPath.trim() ||
    (createDialog.mode === "existing" && createAvailableBranches.length === 0);

  if (collapsed) {
    return (
      <>
        <div className="flex w-[48px] shrink-0 flex-col items-center border-r border-border bg-bg-raised py-3">
          <button
            onClick={() => setCollapsed(false)}
            className="mb-4 flex h-8 w-8 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
            title="Expand sidebar"
          >
            <PanelLeftOpen size={16} />
          </button>
          {repos.map((repo) => (
            <button
              key={repo.path}
              className="mb-1 flex h-8 w-8 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
              title={repo.name}
            >
              <BookOpen size={14} />
            </button>
          ))}
          <button
            onClick={onOpenSettings}
            className="mt-auto flex h-8 w-8 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
            title="Settings"
          >
            <Settings size={14} />
          </button>
        </div>
        {createDialog && createRepo && (
          <div className="fixed inset-0 z-20 flex items-center justify-center bg-black/50 p-4">
            <form
              onSubmit={handleCreateSubmit}
              className="w-full max-w-md rounded-lg border border-border bg-bg-overlay shadow-2xl"
            >
              <div className="flex items-center border-b border-border-subtle px-4 py-3">
                <div className="flex-1">
                  <h3 className="text-sm font-semibold text-fg">Create worktree</h3>
                  <p className="mt-1 text-xs text-fg-muted">{createRepo.name}</p>
                </div>
                <button
                  type="button"
                  onClick={() => setCreateDialog(null)}
                  className="flex h-7 w-7 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
                  title="Close create worktree dialog"
                >
                  <X size={14} />
                </button>
              </div>

              <div className="space-y-4 px-4 py-4">
                <div>
                  <p className="mb-2 text-[11px] font-semibold uppercase tracking-wider text-fg-subtle">
                    Branch mode
                  </p>
                  <div className="grid grid-cols-2 gap-2">
                    <button
                      type="button"
                      onClick={() => handleCreateModeChange("existing")}
                      disabled={createAvailableBranches.length === 0}
                      className={`rounded border px-3 py-2 text-left text-xs transition-colors ${
                        createDialog.mode === "existing"
                          ? "border-accent bg-accent-bg text-accent-fg"
                          : "border-border bg-bg-raised text-fg-muted hover:border-border-hover hover:text-fg"
                      } disabled:cursor-not-allowed disabled:opacity-50`}
                    >
                      Existing branch
                    </button>
                    <button
                      type="button"
                      onClick={() => handleCreateModeChange("new")}
                      className={`rounded border px-3 py-2 text-left text-xs transition-colors ${
                        createDialog.mode === "new"
                          ? "border-accent bg-accent-bg text-accent-fg"
                          : "border-border bg-bg-raised text-fg-muted hover:border-border-hover hover:text-fg"
                      }`}
                    >
                      New branch
                    </button>
                  </div>
                </div>

                {createDialog.mode === "existing" ? (
                  <label className="block text-xs text-fg-muted">
                    Branch
                    <select
                      value={createDialog.branchName}
                      onChange={(event) => handleCreateBranchNameChange(event.target.value)}
                      className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 text-sm text-fg outline-none transition-colors focus:border-accent"
                    >
                      {createAvailableBranches.map((branchName) => (
                        <option key={branchName} value={branchName}>
                          {branchName}
                        </option>
                      ))}
                    </select>
                  </label>
                ) : (
                  <label className="block text-xs text-fg-muted">
                    New branch name
                    <input
                      value={createDialog.branchName}
                      onChange={(event) => handleCreateBranchNameChange(event.target.value)}
                      placeholder="feature/my-worktree"
                      autoComplete="off"
                      autoCorrect="off"
                      autoCapitalize="off"
                      spellCheck={false}
                      className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 text-sm text-fg outline-none transition-colors placeholder:text-fg-subtle focus:border-accent"
                    />
                  </label>
                )}

                <label className="block text-xs text-fg-muted">
                  Target path
                  <input
                    value={createDialog.targetPath}
                    onChange={(event) =>
                      updateCreateDialog((current) => ({
                        ...current,
                        targetPath: event.target.value,
                        pathEdited: true,
                        error: null,
                      }))
                    }
                    autoComplete="off"
                    autoCorrect="off"
                    autoCapitalize="off"
                    spellCheck={false}
                    className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 text-sm text-fg outline-none transition-colors focus:border-accent"
                  />
                </label>

                {createDialog.error && (
                  <div className="rounded bg-red-bg px-3 py-2 text-xs text-red">
                    {createDialog.error}
                  </div>
                )}
              </div>

              <div className="flex items-center justify-end gap-2 border-t border-border-subtle px-4 py-3">
                <button
                  type="button"
                  onClick={() => setCreateDialog(null)}
                  className="rounded border border-border px-3 py-2 text-xs text-fg-muted transition-colors hover:border-border-hover hover:text-fg"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={createSubmitDisabled}
                  className="rounded bg-accent px-3 py-2 text-xs font-medium text-white transition-colors hover:bg-accent-hover disabled:cursor-not-allowed disabled:opacity-60"
                >
                  {createWorktreeMutation.isPending ? "Creating..." : "Create worktree"}
                </button>
              </div>
            </form>
          </div>
        )}
        {deleteDialog && (
          <div className="fixed inset-0 z-20 flex items-center justify-center bg-black/50 p-4">
            <div className="w-full max-w-md rounded-lg border border-border bg-bg-overlay shadow-2xl">
              <div className="flex items-center border-b border-border-subtle px-4 py-3">
                <div className="flex-1">
                  <h3 className="text-sm font-semibold text-fg">Delete worktree</h3>
                  <p className="mt-1 text-xs text-fg-muted">{deleteDialog.worktree.branch}</p>
                </div>
                <button
                  type="button"
                  onClick={() => setDeleteDialog(null)}
                  className="flex h-7 w-7 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
                  title="Close delete worktree dialog"
                >
                  <X size={14} />
                </button>
              </div>

              <div className="space-y-3 px-4 py-4">
                <p className="text-sm text-fg-muted">
                  Remove this worktree checkout and delete its branch.
                </p>
                <div className="rounded border border-border bg-bg-raised px-3 py-2 text-xs text-fg-muted">
                  <div>Branch: {deleteDialog.worktree.branch}</div>
                  <div className="mt-1 break-all">Path: {deleteDialog.worktree.path}</div>
                </div>
                {deleteDialog.error && (
                  <div className="rounded bg-red-bg px-3 py-2 text-xs text-red">
                    {deleteDialog.error}
                  </div>
                )}
              </div>

              <div className="flex items-center justify-end gap-2 border-t border-border-subtle px-4 py-3">
                <button
                  type="button"
                  onClick={() => setDeleteDialog(null)}
                  className="rounded border border-border px-3 py-2 text-xs text-fg-muted transition-colors hover:border-border-hover hover:text-fg"
                >
                  Cancel
                </button>
                {deleteDialog.forceAvailable && (
                  <button
                    type="button"
                    onClick={() => void handleDeleteSubmit(true)}
                    disabled={deleteWorktreeMutation.isPending}
                    className="rounded border border-red px-3 py-2 text-xs font-medium text-red transition-colors hover:bg-red-bg disabled:cursor-not-allowed disabled:opacity-60"
                  >
                    Force delete
                  </button>
                )}
                <button
                  type="button"
                  onClick={() => void handleDeleteSubmit(false)}
                  disabled={deleteWorktreeMutation.isPending}
                  className="rounded bg-red px-3 py-2 text-xs font-medium text-white transition-colors hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60"
                >
                  {deleteWorktreeMutation.isPending ? "Deleting..." : "Delete worktree"}
                </button>
              </div>
            </div>
          </div>
        )}
      </>
    );
  }

  return (
    <>
      <div
        className="flex shrink-0 flex-col border-r border-border bg-bg-raised"
        style={{ width }}
      >
        <div className="flex items-center border-b border-border-subtle p-4">
          <h2 className="flex flex-1 items-center gap-2 text-[15px] font-semibold text-fg">
            <FolderGit2 size={18} />
            Repositories
          </h2>
          <button
            onClick={handleAddRepo}
            className="flex h-6 w-6 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
            title="Add repository"
          >
            <FolderPlus size={14} />
          </button>
          <button
            onClick={() => setCollapsed(true)}
            className="flex h-6 w-6 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
            title="Collapse sidebar"
          >
            <PanelLeftClose size={14} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto py-3">
          <button
            onClick={() => setRepoListCollapsed(!repoListCollapsed)}
            className="mb-1 flex w-full items-center gap-2 px-4 text-left"
          >
            {repoListCollapsed ? (
              <ChevronRight size={10} className="text-fg-subtle" />
            ) : (
              <ChevronDown size={10} className="text-fg-subtle" />
            )}
            <span className="text-[10px] font-semibold uppercase tracking-wider text-fg-subtle">
              Active
            </span>
            {isLoading && <Loader2 size={10} className="animate-spin text-fg-subtle" />}
          </button>

          {error && !repoListCollapsed && (
            <div className="px-4 py-2 text-[11px] text-red">Failed to load repos</div>
          )}

          {sidebarError && !repoListCollapsed && (
            <div className="mx-4 mb-2 rounded bg-red-bg px-2 py-1.5 text-[11px] text-red">
              {sidebarError}
              <button
                onClick={() => setSidebarError(null)}
                className="ml-1 text-fg-subtle hover:text-fg"
              >
                <X size={10} className="inline" />
              </button>
            </div>
          )}

          {!repoListCollapsed &&
            repos.map((repo) => {
              const repoRefreshing = isRepoRefreshing(refreshingRepoPath, repo.path);

              return (
                <div key={repo.path}>
                  <div className="group flex items-center">
                    <button
                      onClick={() => toggleRepo(repo.path)}
                      className="flex flex-1 items-center gap-2.5 px-4 py-[7px] text-[13px] text-fg-muted transition-colors hover:bg-bg-hover hover:text-fg"
                    >
                      {expandedRepos.has(repo.path) ? (
                        <ChevronDown size={14} />
                      ) : (
                        <ChevronRight size={14} />
                      )}
                      <BookOpen size={14} />
                      {repo.name}
                      <span className="ml-auto rounded-lg bg-bg-hover px-1.5 text-[10px] text-fg-subtle">
                        {repo.branches.length}
                      </span>
                    </button>
                    <button
                      onClick={(event) => {
                        event.stopPropagation();
                        handleOpenCreateDialog(repo);
                      }}
                      className="mr-1 flex h-5 w-5 items-center justify-center rounded transition-opacity hover:bg-bg-hover opacity-0 group-hover:opacity-100"
                      title="Create worktree"
                    >
                      <Plus size={12} className="text-fg-subtle" />
                    </button>
                    <button
                      onClick={(event) => {
                        event.stopPropagation();
                        void handleRefreshRepo(repo.path);
                      }}
                      disabled={repoRefreshing}
                      className={`mr-1 flex h-5 w-5 items-center justify-center rounded transition-opacity hover:bg-bg-hover ${
                        repoRefreshing ? "opacity-100" : "opacity-0 group-hover:opacity-100"
                      } disabled:cursor-wait disabled:opacity-100`}
                      title="Refresh repo worktrees"
                    >
                      {repoRefreshing ? (
                        <Loader2 size={12} className="animate-spin text-fg-subtle" />
                      ) : (
                        <RefreshCw size={12} className="text-fg-subtle" />
                      )}
                    </button>
                    <button
                      onClick={(event) => {
                        event.stopPropagation();
                        if (repo.registered) {
                          unregisterMutation.mutate(repo.path);
                        } else {
                          blockRepoMutation.mutate(repo.path);
                        }
                      }}
                      className="mr-2 flex h-5 w-5 items-center justify-center rounded opacity-0 transition-opacity hover:bg-bg-hover group-hover:opacity-100"
                      title="Remove repo"
                    >
                      <X size={12} className="text-fg-subtle" />
                    </button>
                  </div>

                  {expandedRepos.has(repo.path) && (
                    <div className="pl-8">
                      {repo.branches.map((branch) => {
                        const worktree = repo.worktrees.find(
                          (candidate) => candidate.branch === branch.name
                        );
                        const isWorktree = worktreeBranches.has(branch.name);
                        const isActive =
                          activeTab.branch === branch.name &&
                          activeTab.repoPath === (worktree?.path ?? repo.path);
                        const canDeleteWorktree =
                          !!worktree &&
                          !worktree.is_main &&
                          activeTab.repoPath !== worktree.path;
                        const canDeleteBranch = !isWorktree && canDeletePlainBranch({
                          branchName: branch.name,
                          branchIsHead: branch.is_head,
                          hasWorktree: false,
                          activeTabBranch: activeTab.branch,
                          activeTabRepoPath: activeTab.repoPath,
                          repoPath: repo.path,
                        });
                        const deleteBranchTitle = branch.is_head
                          ? "Cannot delete the current repo HEAD branch"
                          : activeTab.branch === branch.name && activeTab.repoPath === repo.path
                            ? "Switch away from this branch before deleting it"
                            : "Delete branch";

                        return (
                          <div key={branch.name} className="group flex items-center">
                            <button
                              onClick={() => {
                                if (worktree) {
                                  onWorktreeSelect(worktree);
                                } else {
                                  onBranchSelect(branch, repo.path);
                                }
                              }}
                              className={`flex flex-1 items-center gap-2 px-2 py-[7px] text-[13px] transition-colors ${
                                isActive
                                  ? "bg-accent-bg text-accent-fg"
                                  : "text-fg-muted hover:bg-bg-hover hover:text-fg"
                              }`}
                            >
                              <GitBranch size={12} />
                              <span className="truncate">{branch.name}</span>
                              {isWorktree ? (
                                <span className="ml-auto rounded bg-green-bg px-1.5 py-0.5 text-[9px] font-medium text-green">
                                  worktree
                                </span>
                              ) : (
                                <span className="ml-auto rounded-lg bg-bg-hover px-1.5 text-[10px] text-fg-subtle">
                                  {branch.checkpoint_count}
                                </span>
                              )}
                            </button>
                            {worktree && !worktree.is_main && (
                              <button
                                onClick={(event) => {
                                  event.stopPropagation();
                                  if (canDeleteWorktree) {
                                    handleOpenDeleteDialog(repo.path, worktree);
                                  }
                                }}
                                disabled={!canDeleteWorktree}
                                className="mr-2 flex h-5 w-5 items-center justify-center rounded opacity-0 transition-opacity hover:bg-bg-hover group-hover:opacity-100 disabled:cursor-not-allowed disabled:opacity-40"
                                title={
                                  canDeleteWorktree
                                    ? "Delete worktree"
                                    : "Switch away from this worktree before deleting it"
                                }
                              >
                                <Trash2 size={12} className="text-fg-subtle" />
                              </button>
                            )}
                            {!worktree && (
                              <button
                                onClick={(event) => {
                                  event.stopPropagation();
                                  if (canDeleteBranch) {
                                    handleOpenDeleteBranchDialog(repo.path, branch.name);
                                  }
                                }}
                                disabled={!canDeleteBranch}
                                className="mr-2 flex h-5 w-5 items-center justify-center rounded opacity-0 transition-opacity hover:bg-bg-hover group-hover:opacity-100 disabled:cursor-not-allowed disabled:opacity-40"
                                title={deleteBranchTitle}
                              >
                                <Trash2 size={12} className="text-fg-subtle" />
                              </button>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })}

          {!repoListCollapsed && repos.length === 0 && !isLoading && !error && (
            <div className="px-4 py-6 text-center text-[11px] text-fg-subtle">
              No repositories discovered
            </div>
          )}
        </div>
      </div>
      <div
        onMouseDown={onResizeStart}
        className="w-[3px] shrink-0 cursor-col-resize bg-border transition-colors hover:bg-accent"
        title="Resize repository sidebar"
      />

      {createDialog && createRepo && (
        <div className="fixed inset-0 z-20 flex items-center justify-center bg-black/50 p-4">
          <form
            onSubmit={handleCreateSubmit}
            className="w-full max-w-md rounded-lg border border-border bg-bg-overlay shadow-2xl"
          >
            <div className="flex items-center border-b border-border-subtle px-4 py-3">
              <div className="flex-1">
                <h3 className="text-sm font-semibold text-fg">Create worktree</h3>
                <p className="mt-1 text-xs text-fg-muted">{createRepo.name}</p>
              </div>
              <button
                type="button"
                onClick={() => setCreateDialog(null)}
                className="flex h-7 w-7 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
                title="Close create worktree dialog"
              >
                <X size={14} />
              </button>
            </div>

            <div className="space-y-4 px-4 py-4">
              <div>
                <p className="mb-2 text-[11px] font-semibold uppercase tracking-wider text-fg-subtle">
                  Branch mode
                </p>
                <div className="grid grid-cols-2 gap-2">
                  <button
                    type="button"
                    onClick={() => handleCreateModeChange("existing")}
                    disabled={createAvailableBranches.length === 0}
                    className={`rounded border px-3 py-2 text-left text-xs transition-colors ${
                      createDialog.mode === "existing"
                        ? "border-accent bg-accent-bg text-accent-fg"
                        : "border-border bg-bg-raised text-fg-muted hover:border-border-hover hover:text-fg"
                    } disabled:cursor-not-allowed disabled:opacity-50`}
                  >
                    Existing branch
                  </button>
                  <button
                    type="button"
                    onClick={() => handleCreateModeChange("new")}
                    className={`rounded border px-3 py-2 text-left text-xs transition-colors ${
                      createDialog.mode === "new"
                        ? "border-accent bg-accent-bg text-accent-fg"
                        : "border-border bg-bg-raised text-fg-muted hover:border-border-hover hover:text-fg"
                    }`}
                  >
                    New branch
                  </button>
                </div>
              </div>

              {createDialog.mode === "existing" ? (
                <label className="block text-xs text-fg-muted">
                  Branch
                  <select
                    value={createDialog.branchName}
                    onChange={(event) => handleCreateBranchNameChange(event.target.value)}
                    className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 text-sm text-fg outline-none transition-colors focus:border-accent"
                  >
                    {createAvailableBranches.map((branchName) => (
                      <option key={branchName} value={branchName}>
                        {branchName}
                      </option>
                    ))}
                  </select>
                </label>
              ) : (
                <label className="block text-xs text-fg-muted">
                  New branch name
                  <input
                    value={createDialog.branchName}
                    onChange={(event) => handleCreateBranchNameChange(event.target.value)}
                    placeholder="feature/my-worktree"
                    autoComplete="off"
                    autoCorrect="off"
                    autoCapitalize="off"
                    spellCheck={false}
                    className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 text-sm text-fg outline-none transition-colors placeholder:text-fg-subtle focus:border-accent"
                  />
                </label>
              )}

              <label className="block text-xs text-fg-muted">
                Target path
                <input
                  value={createDialog.targetPath}
                  onChange={(event) =>
                    updateCreateDialog((current) => ({
                      ...current,
                      targetPath: event.target.value,
                      pathEdited: true,
                      error: null,
                    }))
                  }
                  autoComplete="off"
                  autoCorrect="off"
                  autoCapitalize="off"
                  spellCheck={false}
                  className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 text-sm text-fg outline-none transition-colors focus:border-accent"
                />
              </label>

              {createDialog.error && (
                <div className="rounded bg-red-bg px-3 py-2 text-xs text-red">
                  {createDialog.error}
                </div>
              )}
            </div>

            <div className="flex items-center justify-end gap-2 border-t border-border-subtle px-4 py-3">
              <button
                type="button"
                onClick={() => setCreateDialog(null)}
                className="rounded border border-border px-3 py-2 text-xs text-fg-muted transition-colors hover:border-border-hover hover:text-fg"
              >
                Cancel
              </button>
              <button
                type="submit"
                disabled={createSubmitDisabled}
                className="rounded bg-accent px-3 py-2 text-xs font-medium text-white transition-colors hover:bg-accent-hover disabled:cursor-not-allowed disabled:opacity-60"
              >
                {createWorktreeMutation.isPending ? "Creating..." : "Create worktree"}
              </button>
            </div>
          </form>
        </div>
      )}

      {deleteBranchDialog && (
        <div className="fixed inset-0 z-20 flex items-center justify-center bg-black/50 p-4">
          <div className="w-full max-w-md rounded-lg border border-border bg-bg-overlay shadow-2xl">
            <div className="flex items-center border-b border-border-subtle px-4 py-3">
              <div className="flex-1">
                <h3 className="text-sm font-semibold text-fg">Delete branch</h3>
                <p className="mt-1 text-xs text-fg-muted">{deleteBranchDialog.branchName}</p>
              </div>
              <button
                type="button"
                onClick={() => setDeleteBranchDialog(null)}
                className="flex h-7 w-7 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
                title="Close delete branch dialog"
              >
                <X size={14} />
              </button>
            </div>

            <div className="space-y-3 px-4 py-4">
              <p className="text-sm text-fg-muted">
                Delete this branch from the main repository checkout.
              </p>
              <div className="rounded border border-border bg-bg-raised px-3 py-2 text-xs text-fg-muted">
                <div>Branch: {deleteBranchDialog.branchName}</div>
                <div className="mt-1 break-all">Repo: {deleteBranchDialog.repoPath}</div>
              </div>
              {deleteBranchDialog.error && (
                <div className="rounded bg-red-bg px-3 py-2 text-xs text-red">
                  {deleteBranchDialog.error}
                </div>
              )}
            </div>

            <div className="flex items-center justify-end gap-2 border-t border-border-subtle px-4 py-3">
              <button
                type="button"
                onClick={() => setDeleteBranchDialog(null)}
                className="rounded border border-border px-3 py-2 text-xs text-fg-muted transition-colors hover:border-border-hover hover:text-fg"
              >
                Cancel
              </button>
              <button
                type="button"
                onClick={() => void handleDeleteBranchSubmit()}
                disabled={deleteBranchMutation.isPending}
                className="rounded bg-red px-3 py-2 text-xs font-medium text-white transition-colors hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60"
              >
                {deleteBranchMutation.isPending ? "Deleting..." : "Delete branch"}
              </button>
            </div>
          </div>
        </div>
      )}

      {deleteDialog && (
        <div className="fixed inset-0 z-20 flex items-center justify-center bg-black/50 p-4">
          <div className="w-full max-w-md rounded-lg border border-border bg-bg-overlay shadow-2xl">
            <div className="flex items-center border-b border-border-subtle px-4 py-3">
              <div className="flex-1">
                <h3 className="text-sm font-semibold text-fg">Delete worktree</h3>
                <p className="mt-1 text-xs text-fg-muted">{deleteDialog.worktree.branch}</p>
              </div>
              <button
                type="button"
                onClick={() => setDeleteDialog(null)}
                className="flex h-7 w-7 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
                title="Close delete worktree dialog"
              >
                <X size={14} />
              </button>
            </div>

            <div className="space-y-3 px-4 py-4">
              <p className="text-sm text-fg-muted">
                Remove this worktree checkout and delete its branch.
              </p>
              <div className="rounded border border-border bg-bg-raised px-3 py-2 text-xs text-fg-muted">
                <div>Branch: {deleteDialog.worktree.branch}</div>
                <div className="mt-1 break-all">Path: {deleteDialog.worktree.path}</div>
              </div>
              {deleteDialog.error && (
                <div className="rounded bg-red-bg px-3 py-2 text-xs text-red">
                  {deleteDialog.error}
                </div>
              )}
            </div>

            <div className="flex items-center justify-end gap-2 border-t border-border-subtle px-4 py-3">
              <button
                type="button"
                onClick={() => setDeleteDialog(null)}
                className="rounded border border-border px-3 py-2 text-xs text-fg-muted transition-colors hover:border-border-hover hover:text-fg"
              >
                Cancel
              </button>
              {deleteDialog.forceAvailable && (
                <button
                  type="button"
                  onClick={() => void handleDeleteSubmit(true)}
                  disabled={deleteWorktreeMutation.isPending}
                  className="rounded border border-red px-3 py-2 text-xs font-medium text-red transition-colors hover:bg-red-bg disabled:cursor-not-allowed disabled:opacity-60"
                >
                  Force delete
                </button>
              )}
              <button
                type="button"
                onClick={() => void handleDeleteSubmit(false)}
                disabled={deleteWorktreeMutation.isPending}
                className="rounded bg-red px-3 py-2 text-xs font-medium text-white transition-colors hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60"
              >
                {deleteWorktreeMutation.isPending ? "Deleting..." : "Delete worktree"}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

import { useState, useEffect, useRef, useCallback } from "react";
import { invoke } from "@tauri-apps/api/core";
import { Sidebar } from "./features/repos/Sidebar";
import { useReposQuery } from "./hooks/use-tauri-query";
import { TitleBar } from "./components/TitleBar";
import { TabBar } from "./components/TabBar";
import { CheckpointList } from "./features/checkpoints/CheckpointList";
import { TranscriptView } from "./features/transcripts/TranscriptView";
import { DiffView, BranchDiffView } from "./features/diff/DiffView";
import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
import { BranchDebugContainer } from "./features/debug/BranchDebugContainer";
import { CheckpointDebugContainer } from "./features/debug/CheckpointDebugContainer";
import { TerminalPanel } from "./features/terminal/TerminalPanel";
import type { TerminalPanelHandle } from "./features/terminal/TerminalPanel";
import { createBranchTab, createWorktreeTab } from "./features/repos/tab-state";
import { DEFAULT_SIDEBAR_WIDTH, clampSidebarWidth } from "./features/repos/sidebar-width.ts";
import { planWorktreeDeletionCleanup } from "./features/repos/worktree-delete-state.ts";
import {
  collectWorkspaceSurfaceIds,
  createTerminalWorkspace,
  type TerminalWorkspace,
  type WorkspaceUpdate,
} from "./features/terminal/workspace";
import {
  createTerminalPanelVisibility,
  isTerminalPanelOpen,
  setTerminalPanelOpen,
  syncTerminalPanelVisibility,
} from "./features/terminal/panel-visibility";
import {
  DEFAULT_TERMINAL_HEIGHT,
  clampTerminalHeight,
} from "./features/terminal/resize.ts";
import { useLiveUpdates } from "./hooks/use-live-updates";
import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
import { ArrowLeft, GitCommit } from "lucide-react";

export interface Tab {
  id: string;
  branch: string;
  repoPath: string;
  worktree: WorktreeInfo | null;
  kind: "branch" | "agent";
  agent: string | null;
  hasActiveSession: boolean;
}

function resolveAgent(agent: string) {
  return agent === "codex" ? "codex" : "claude-code";
}

export default function App() {
  const [tabs, setTabs] = useState<Tab[]>([
    {
      id: "main",
      branch: "main",
      repoPath: "",
      worktree: null,
      kind: "branch",
      agent: null,
      hasActiveSession: false,
    },
  ]);
  const [activeTabId, setActiveTabId] = useState("main");
  const [sidebarWidth, setSidebarWidth] = useState(DEFAULT_SIDEBAR_WIDTH);
  const [terminalHeight, setTerminalHeight] = useState(() => {
    const storedHeight = Number(localStorage.getItem("entire:terminal-height"));
    const initialHeight = Number.isFinite(storedHeight) && storedHeight > 0
      ? storedHeight
      : DEFAULT_TERMINAL_HEIGHT;

    return clampTerminalHeight(initialHeight, window.innerHeight);
  });
  const [checkpointListWidth, setCheckpointListWidth] = useState(() => {
    const stored = Number(localStorage.getItem("entire:checkpoint-list-width"));
    return Number.isFinite(stored) && stored >= 200 ? Math.min(stored, 500) : 320;
  });
  const [terminalPanelVisibility, setTerminalPanelVisibility] = useState(
    () => createTerminalPanelVisibility(["main"])
  );
  const [innerTab, setInnerTab] = useState<
    "checkpoints" | "diff" | "insights" | "debug"
  >("checkpoints");
  const [selectedCheckpoint, setSelectedCheckpoint] =
    useState<CheckpointSummary | null>(null);
  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
    "transcript" | "diff" | "insights" | "debug"
  >("transcript");

  const [workspaceMap, setWorkspaceMap] = useState<Map<string, TerminalWorkspace>>(
    () => new Map([["main", createTerminalWorkspace()]])
  );
  const [pendingAgentLaunch, setPendingAgentLaunch] = useState<{
    tabId: string;
    agent: string;
    prompt: string;
  } | null>(null);
  const [isSidebarDialogOpen, setIsSidebarDialogOpen] = useState(false);

  const terminalRef = useRef<TerminalPanelHandle>(null);

  // Load repos so we can auto-populate the initial tab
  const { data: repos } = useReposQuery();

  // Auto-populate the initial tab's repoPath from the first discovered repo
  useEffect(() => {
    invoke("debug_log", {
      message: `useEffect[repos]: repos=${repos ? repos.length : "null"}, first repo path=${repos?.[0]?.path ?? "none"}`,
    }).catch(() => {});

    if (!repos || repos.length === 0) return;
    setTabs((prev) => {
      const updated = prev.map((tab) => {
        if (tab.id === "main" && !tab.repoPath) {
          const repo = repos[0];
          const headBranch = repo.branches.find((b: { is_head: boolean }) => b.is_head);
          const newPath = repo.path;
          const newBranch = headBranch?.name ?? repo.branches[0]?.name ?? "main";
          invoke("debug_log", {
            message: `Auto-populating initial tab: repoPath=${newPath}, branch=${newBranch}`,
          }).catch(() => {});
          return {
            ...tab,
            repoPath: newPath,
            branch: newBranch,
          };
        }
        return tab;
      });
      return updated;
    });
  }, [repos]);

  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
  const activeWorkspace =
    workspaceMap.get(activeTabId) ?? createTerminalWorkspace();
  const isTerminalOpen = isTerminalPanelOpen(terminalPanelVisibility, activeTabId);
  const tabsWithSessions = tabs.map((tab) => ({
    ...tab,
    hasActiveSession: collectWorkspaceSurfaceIds(workspaceMap.get(tab.id)).length > 0,
  }));

  // Live updates — watch active repo for checkpoint/session changes
  useLiveUpdates(activeTab.repoPath);

  useEffect(() => {
    setWorkspaceMap((prev) => {
      let changed = false;
      const next = new Map(prev);
      for (const tab of tabs) {
        if (!next.has(tab.id)) {
          next.set(tab.id, createTerminalWorkspace());
          changed = true;
        }
      }
      return changed ? next : prev;
    });
  }, [tabs]);

  useEffect(() => {
    setTerminalPanelVisibility((prev) =>
      syncTerminalPanelVisibility(
        prev,
        tabs.map((tab) => tab.id)
      )
    );
  }, [tabs]);

  const handleWorkspaceChange = useCallback(
    (tabId: string, update: WorkspaceUpdate) => {
      setWorkspaceMap((prev) => {
        const next = new Map(prev);
        const current = next.get(tabId) ?? createTerminalWorkspace();
        next.set(
          tabId,
          typeof update === "function" ? update(current) : update
        );
        return next;
      });
    },
    []
  );

  const handleSetTerminalOpen = useCallback((tabId: string, isOpen: boolean) => {
    setTerminalPanelVisibility((prev) => setTerminalPanelOpen(prev, tabId, isOpen));
  }, []);

  // Terminal dispatch — open shell and optionally send a prompt
  const handleSendToAgent = useCallback(
    (agent: string, prompt: string) => {
      if (!activeTab.repoPath) return;

      const resolvedAgent = resolveAgent(agent);
      const tabId = `agent:${resolvedAgent}:${Date.now()}`;
      const agentTab: Tab = {
        id: tabId,
        branch: activeTab.branch,
        repoPath: activeTab.repoPath,
        worktree: activeTab.worktree,
        kind: "agent",
        agent: resolvedAgent,
        hasActiveSession: false,
      };

      setTabs((prev) => [...prev, agentTab]);
      setActiveTabId(tabId);
      handleSetTerminalOpen(tabId, true);
      setPendingAgentLaunch({ tabId, agent: resolvedAgent, prompt });
    },
    [activeTab, handleSetTerminalOpen]
  );

  useEffect(() => {
    if (!pendingAgentLaunch) return;
    if (pendingAgentLaunch.tabId !== activeTabId) return;
    if (!isTerminalOpen) return;

    let cancelled = false;
    let timer = 0;

    const launch = () => {
      if (cancelled) return;
      if (!terminalRef.current) {
        timer = window.setTimeout(launch, 50);
        return;
      }

      terminalRef.current
        .launchSession({
          agent: pendingAgentLaunch.agent,
          prompt: pendingAgentLaunch.prompt,
        })
        .finally(() => {
          setPendingAgentLaunch((current) =>
            current?.tabId === pendingAgentLaunch.tabId ? null : current
          );
        });
    };

    timer = window.setTimeout(launch, 50);
    return () => {
      cancelled = true;
      window.clearTimeout(timer);
    };
  }, [activeTabId, isTerminalOpen, pendingAgentLaunch]);

  // Persist UI state to localStorage
  useEffect(() => {
    localStorage.setItem("entire:terminal-height", String(terminalHeight));
  }, [terminalHeight]);
  useEffect(() => {
    localStorage.setItem("entire:checkpoint-list-width", String(checkpointListWidth));
  }, [checkpointListWidth]);
  useEffect(() => {
    function handleWindowResize() {
      setTerminalHeight((currentHeight) =>
        clampTerminalHeight(currentHeight, window.innerHeight)
      );
    }

    window.addEventListener("resize", handleWindowResize);
    return () => window.removeEventListener("resize", handleWindowResize);
  }, []);

  // Clear selected checkpoint when switching branch tabs
  useEffect(() => {
    setSelectedCheckpoint(null);
    setCheckpointInnerTab("transcript");
  }, [activeTabId]);

  // Keyboard shortcuts
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      const meta = e.metaKey || e.ctrlKey;

      // Cmd+K = focus search
      if (meta && e.key === "k") {
        e.preventDefault();
        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
      }
      // Ctrl+` = toggle terminal
      if (e.ctrlKey && e.key === "`") {
        e.preventDefault();
        handleSetTerminalOpen(activeTabId, !isTerminalOpen);
      }
      // Cmd+W = close active tab
      if (meta && e.key === "w") {
        e.preventDefault();
        handleCloseTab(activeTabId);
      }
      // Cmd+1-9 = switch to tab by index
      if (meta && e.key >= "1" && e.key <= "9") {
        e.preventDefault();
        const idx = parseInt(e.key) - 1;
        if (idx < tabs.length) {
          setActiveTabId(tabs[idx].id);
        }
      }
      // Cmd+[ / Cmd+] = prev/next tab
      if (meta && e.key === "[") {
        e.preventDefault();
        const idx = tabs.findIndex((t) => t.id === activeTabId);
        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
      }
      if (meta && e.key === "]") {
        e.preventDefault();
        const idx = tabs.findIndex((t) => t.id === activeTabId);
        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
      }
      // Escape = deselect checkpoint
      if (e.key === "Escape" && selectedCheckpoint) {
        setSelectedCheckpoint(null);
      }
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [activeTabId, handleSetTerminalOpen, isTerminalOpen, tabs, selectedCheckpoint]);

  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
    const newTab = createBranchTab(branch, repoPath);
    const existing = tabs.find(
      (t) =>
        t.kind === "branch" &&
        t.branch === newTab.branch &&
        t.repoPath === newTab.repoPath
    );
    if (existing) {
      setActiveTabId(existing.id);
    } else {
      setTabs([...tabs, newTab]);
      setActiveTabId(newTab.id);
    }
  }

  function handleWorktreeSelect(wt: WorktreeInfo) {
    const newTab = createWorktreeTab(wt);
    const existing = tabs.find(
      (t) =>
        t.kind === "branch" &&
        t.branch === newTab.branch &&
        t.repoPath === newTab.repoPath
    );
    if (existing) {
      setActiveTabId(existing.id);
    } else {
      setTabs([...tabs, newTab]);
      setActiveTabId(newTab.id);
    }
  }

  function handleCloseTab(tabId: string) {
    if (tabs.length <= 1) return;
    const idx = tabs.findIndex((t) => t.id === tabId);
    const newTabs = tabs.filter((t) => t.id !== tabId);
    setTabs(newTabs);
    if (activeTabId === tabId) {
      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
    }
    const closedWorkspace = workspaceMap.get(tabId);
    for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
      invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
    }
    setWorkspaceMap((prev) => {
      const next = new Map(prev);
      next.delete(tabId);
      return next;
    });
  }

  function handleBranchDeleted(branchName: string, repoPath: string) {
    const tabsToRemove = tabs.filter(
      (tab) =>
        tab.kind === "branch" &&
        tab.worktree === null &&
        tab.branch === branchName &&
        tab.repoPath === repoPath
    );

    if (tabsToRemove.length === 0) {
      return;
    }

    const nextTabs = tabs.filter((tab) => !tabsToRemove.some((candidate) => candidate.id === tab.id));
    setTabs(nextTabs);

    if (tabsToRemove.some((tab) => tab.id === activeTabId) && nextTabs.length > 0) {
      setActiveTabId(nextTabs[0].id);
    }

    setWorkspaceMap((prev) => {
      const next = new Map(prev);
      for (const tab of tabsToRemove) {
        const closedWorkspace = next.get(tab.id);
        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
        }
        next.delete(tab.id);
      }
      return next;
    });
  }

  function handleWorktreeDeleted(worktreePath: string) {
    const cleanup = planWorktreeDeletionCleanup({
      tabs,
      activeTabId,
      worktreePath,
    });

    if (cleanup.removedTabIds.length === 0) {
      return;
    }

    setTabs(cleanup.remainingTabs);

    if (cleanup.nextActiveTabId && cleanup.nextActiveTabId !== activeTabId) {
      setActiveTabId(cleanup.nextActiveTabId);
    }

    setWorkspaceMap((prev) => {
      const next = new Map(prev);
      for (const tabId of cleanup.removedTabIds) {
        const closedWorkspace = next.get(tabId);
        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
        }
        next.delete(tabId);
      }
      return next;
    });
  }

  function handleResizeStart(e: React.MouseEvent) {
    e.preventDefault();
    const startY = e.clientY;
    const startHeight = terminalHeight;

    function onMouseMove(ev: MouseEvent) {
      const delta = startY - ev.clientY;
      setTerminalHeight(
        clampTerminalHeight(startHeight + delta, window.innerHeight)
      );
    }
    function onMouseUp() {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    }
    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
  }

  function handleSidebarResizeStart(e: React.MouseEvent<HTMLDivElement>) {
    e.preventDefault();
    const startX = e.clientX;
    const startWidth = sidebarWidth;

    function onMouseMove(ev: MouseEvent) {
      const delta = ev.clientX - startX;
      setSidebarWidth(clampSidebarWidth(startWidth + delta));
    }

    function onMouseUp() {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    }

    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
  }

  function handleCheckpointListResizeStart(e: React.MouseEvent<HTMLDivElement>) {
    e.preventDefault();
    const startX = e.clientX;
    const startWidth = checkpointListWidth;

    function onMouseMove(ev: MouseEvent) {
      const delta = ev.clientX - startX;
      setCheckpointListWidth(Math.max(200, Math.min(500, startWidth + delta)));
    }

    function onMouseUp() {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    }

    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
  }

  const repoName = activeTab.repoPath
    ? activeTab.repoPath.split("/").pop()
    : "";

  return (
    <div className="flex h-screen flex-col">
      <TitleBar
        title={`Entire — ${repoName ? `${repoName}/` : ""}${activeTab?.branch ?? ""}`}
      />

      <div className="flex flex-1 overflow-hidden">
        {/* Sidebar */}
        <Sidebar
          activeTab={activeTab}
          width={sidebarWidth}
          onBranchSelect={handleBranchSelect}
          onBranchDeleted={handleBranchDeleted}
          onWorktreeDeleted={handleWorktreeDeleted}
          onWorktreeSelect={handleWorktreeSelect}
          onResizeStart={handleSidebarResizeStart}
          onDialogOpen={setIsSidebarDialogOpen}
        />

        {/* Main content */}
        <div className="flex flex-1 flex-col overflow-hidden">
          <TabBar
            tabs={tabsWithSessions}
            activeTabId={activeTabId}
            onSelectTab={setActiveTabId}
            onCloseTab={handleCloseTab}
          />

          <div className="flex flex-1 flex-col overflow-hidden">
            {/* Inner tabs */}
            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
              {(["checkpoints", "diff", "insights", "debug"] as const).map((tab) => (
                <button
                  key={tab}
                  onClick={() => setInnerTab(tab)}
                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
                    innerTab === tab
                      ? "border-accent text-fg"
                      : "border-transparent text-fg-subtle hover:text-fg-muted"
                  }`}
                >
                  {tab === "checkpoints"
                    ? "Checkpoints"
                    : tab === "diff"
                      ? "Diff"
                      : tab === "insights"
                        ? "Insights"
                        : "Debug"}
                </button>
              ))}
            </div>

            {/* Main view */}
            <div className="flex flex-1 overflow-hidden bg-bg">
              {innerTab === "checkpoints" && (
                <>
                  {/* Checkpoint list — always visible when on checkpoints tab */}
                  <div
                    className={`overflow-y-auto ${
                      selectedCheckpoint
                        ? "shrink-0 border-r border-border-subtle"
                        : "flex-1"
                    }`}
                    style={selectedCheckpoint ? { width: checkpointListWidth } : undefined}
                  >
                    <CheckpointList
                      repoPath={activeTab.repoPath}
                      branch={activeTab.branch}
                      onSelectCheckpoint={(cp) => {
                        setSelectedCheckpoint(cp);
                        setCheckpointInnerTab("transcript");
                      }}
                    />
                  </div>

                  {/* Checkpoint list resize handle */}
                  {selectedCheckpoint && (
                    <div
                      onMouseDown={handleCheckpointListResizeStart}
                      className="w-[3px] shrink-0 cursor-col-resize bg-border transition-colors hover:bg-accent"
                    />
                  )}

                  {/* Checkpoint detail panel */}
                  {selectedCheckpoint && (
                    <div className="flex flex-1 flex-col overflow-hidden">
                      {/* Detail header */}
                      <div className="flex items-center gap-3 border-b border-border-subtle px-4 py-2.5">
                        <button
                          onClick={() => setSelectedCheckpoint(null)}
                          className="flex items-center gap-1.5 text-xs text-fg-subtle transition-colors hover:text-fg"
                        >
                          <ArrowLeft size={14} />
                        </button>
                        <GitCommit size={14} className="text-fg-subtle" />
                        <span className="font-mono text-xs text-accent-fg">
                          {selectedCheckpoint.commit_sha
                            ? selectedCheckpoint.commit_sha.slice(0, 7)
                            : selectedCheckpoint.checkpoint_id.slice(0, 7)}
                        </span>
                        <span className="truncate text-xs text-fg-muted">
                          {selectedCheckpoint.commit_message || "Untitled"}
                        </span>
                      </div>

                      {/* Checkpoint sub-tabs */}
                      <div className="flex gap-0 border-b border-border-subtle bg-bg px-4 pt-2">
                        {(["transcript", "diff", "insights", "debug"] as const).map(
                          (tab) => (
                            <button
                              key={tab}
                              onClick={() => setCheckpointInnerTab(tab)}
                              className={`border-b-2 px-3 pb-1.5 text-[11px] font-medium capitalize transition-colors ${
                                checkpointInnerTab === tab
                                  ? "border-accent text-fg"
                                  : "border-transparent text-fg-subtle hover:text-fg-muted"
                              }`}
                            >
                              {tab === "transcript"
                                ? "Transcript"
                                : tab === "diff"
                                  ? "Diff"
                                  : tab === "insights"
                                    ? "Insights"
                                    : "Debug"}
                            </button>
                          )
                        )}
                      </div>

                      {/* Checkpoint detail content */}
                      <div className="flex-1 overflow-y-auto">
                        {checkpointInnerTab === "transcript" && (
                          <TranscriptView
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                          />
                        )}
                        {checkpointInnerTab === "diff" && (
                          <DiffView
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                            onSendToAgent={handleSendToAgent}
                          />
                        )}
                        {checkpointInnerTab === "insights" && (
                          <CheckpointInsightsContainer
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                          />
                        )}
                        {checkpointInnerTab === "debug" && (
                          <CheckpointDebugContainer
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                          />
                        )}
                      </div>
                    </div>
                  )}
                </>
              )}
              {innerTab === "diff" && (
                <div className="flex flex-1 overflow-hidden">
                  <BranchDiffView
                    repoPath={activeTab.repoPath}
                    branch={activeTab.branch}
                    onSendToAgent={handleSendToAgent}
                  />
                </div>
              )}
              {innerTab === "insights" && (
                <div className="flex flex-1 overflow-y-auto">
                  <BranchInsightsContainer
                    repoPath={activeTab.repoPath}
                    branch={activeTab.branch}
                  />
                </div>
              )}
              {innerTab === "debug" && (
                <div className="flex flex-1 overflow-y-auto">
                  <BranchDebugContainer
                    repoPath={activeTab.repoPath}
                    branch={activeTab.branch}
                  />
                </div>
              )}
            </div>

            {/* Resize handle */}
            {isTerminalOpen && (
              <div
                onMouseDown={handleResizeStart}
                className="h-[3px] shrink-0 cursor-row-resize bg-border transition-colors hover:bg-accent"
              />
            )}

            {/* Terminal panel */}
            {isTerminalOpen && (
              <TerminalPanel
                ref={terminalRef}
                height={terminalHeight}
                tab={activeTab}
                workspace={activeWorkspace}
                onWorkspaceChange={(update) =>
                  handleWorkspaceChange(activeTab.id, update)
                }
                onToggle={() => handleSetTerminalOpen(activeTab.id, false)}
                dialogOpen={isSidebarDialogOpen}
              />
            )}
          </div>
        </div>
      </div>

      {!isTerminalOpen && (
        <button
          onClick={() => handleSetTerminalOpen(activeTab.id, true)}
          className="flex h-7 shrink-0 items-center justify-center border-t border-border bg-bg-raised text-[11px] text-fg-subtle hover:text-fg-muted"
        >
          ▲ Terminal (⌃`)
        </button>
      )}
    </div>
  );
}

import { useState, useEffect, useRef, useCallback } from "react";
import { invoke } from "@tauri-apps/api/core";
import { Sidebar } from "./features/repos/Sidebar";
import { useReposQuery } from "./hooks/use-tauri-query";
import { TitleBar } from "./components/TitleBar";
import { TabBar } from "./components/TabBar";
import { CheckpointList } from "./features/checkpoints/CheckpointList";
import { TranscriptView } from "./features/transcripts/TranscriptView";
import { DiffView, BranchDiffView } from "./features/diff/DiffView";
import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
import { BranchDebugContainer } from "./features/debug/BranchDebugContainer";
import { CheckpointDebugContainer } from "./features/debug/CheckpointDebugContainer";
import { TerminalPanel } from "./features/terminal/TerminalPanel";
import type { TerminalPanelHandle } from "./features/terminal/TerminalPanel";
import { createBranchTab, createWorktreeTab } from "./features/repos/tab-state";
import { DEFAULT_SIDEBAR_WIDTH, clampSidebarWidth } from "./features/repos/sidebar-width.ts";
import { planWorktreeDeletionCleanup } from "./features/repos/worktree-delete-state.ts";
import {
  collectWorkspaceSurfaceIds,
  createTerminalWorkspace,
  type TerminalWorkspace,
  type WorkspaceUpdate,
} from "./features/terminal/workspace";
import {
  createTerminalPanelVisibility,
  isTerminalPanelOpen,
  setTerminalPanelOpen,
  syncTerminalPanelVisibility,
} from "./features/terminal/panel-visibility";
import {
  DEFAULT_TERMINAL_HEIGHT,
  clampTerminalHeight,
} from "./features/terminal/resize.ts";
import { useLiveUpdates } from "./hooks/use-live-updates";
import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
import { SettingsView } from "./features/settings/SettingsView";
import { ArrowLeft, GitCommit } from "lucide-react";

export interface Tab {
  id: string;
  branch: string;
  repoPath: string;
  worktree: WorktreeInfo | null;
  kind: "branch" | "agent";
  agent: string | null;
  hasActiveSession: boolean;
}

function resolveAgent(agent: string) {
  return agent === "codex" ? "codex" : "claude-code";
}

export default function App() {
  const [tabs, setTabs] = useState<Tab[]>([
    {
      id: "main",
      branch: "main",
      repoPath: "",
      worktree: null,
      kind: "branch",
      agent: null,
      hasActiveSession: false,
    },
  ]);
  const [activeTabId, setActiveTabId] = useState("main");
  const [sidebarWidth, setSidebarWidth] = useState(DEFAULT_SIDEBAR_WIDTH);
  const [terminalHeight, setTerminalHeight] = useState(() => {
    const storedHeight = Number(localStorage.getItem("entire:terminal-height"));
    const initialHeight = Number.isFinite(storedHeight) && storedHeight > 0
      ? storedHeight
      : DEFAULT_TERMINAL_HEIGHT;

    return clampTerminalHeight(initialHeight, window.innerHeight);
  });
  const [checkpointListWidth, setCheckpointListWidth] = useState(() => {
    const stored = Number(localStorage.getItem("entire:checkpoint-list-width"));
    return Number.isFinite(stored) && stored >= 200 ? Math.min(stored, 500) : 320;
  });
  const [terminalPanelVisibility, setTerminalPanelVisibility] = useState(
    () => createTerminalPanelVisibility(["main"])
  );
  const [innerTab, setInnerTab] = useState<
    "checkpoints" | "diff" | "insights" | "debug"
  >("checkpoints");
  const [selectedCheckpoint, setSelectedCheckpoint] =
    useState<CheckpointSummary | null>(null);
  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
    "transcript" | "diff" | "insights" | "debug"
  >("transcript");

  const [workspaceMap, setWorkspaceMap] = useState<Map<string, TerminalWorkspace>>(
    () => new Map([["main", createTerminalWorkspace()]])
  );
  const [pendingAgentLaunch, setPendingAgentLaunch] = useState<{
    tabId: string;
    agent: string;
    prompt: string;
  } | null>(null);
  const [isSidebarDialogOpen, setIsSidebarDialogOpen] = useState(false);

  const terminalRef = useRef<TerminalPanelHandle>(null);

  // Load repos so we can auto-populate the initial tab
  const { data: repos } = useReposQuery();

  // Auto-populate the initial tab's repoPath from the first discovered repo
  useEffect(() => {
    invoke("debug_log", {
      message: `useEffect[repos]: repos=${repos ? repos.length : "null"}, first repo path=${repos?.[0]?.path ?? "none"}`,
    }).catch(() => {});

    if (!repos || repos.length === 0) return;
    setTabs((prev) => {
      const updated = prev.map((tab) => {
        if (tab.id === "main" && !tab.repoPath) {
          const repo = repos[0];
          const headBranch = repo.branches.find((b: { is_head: boolean }) => b.is_head);
          const newPath = repo.path;
          const newBranch = headBranch?.name ?? repo.branches[0]?.name ?? "main";
          invoke("debug_log", {
            message: `Auto-populating initial tab: repoPath=${newPath}, branch=${newBranch}`,
          }).catch(() => {});
          return {
            ...tab,
            repoPath: newPath,
            branch: newBranch,
          };
        }
        return tab;
      });
      return updated;
    });
  }, [repos]);

  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
  const activeWorkspace =
    workspaceMap.get(activeTabId) ?? createTerminalWorkspace();
  const isTerminalOpen = isTerminalPanelOpen(terminalPanelVisibility, activeTabId);
  const tabsWithSessions = tabs.map((tab) => ({
    ...tab,
    hasActiveSession: collectWorkspaceSurfaceIds(workspaceMap.get(tab.id)).length > 0,
  }));

  // Live updates — watch active repo for checkpoint/session changes
  useLiveUpdates(activeTab.repoPath);

  useEffect(() => {
    setWorkspaceMap((prev) => {
      let changed = false;
      const next = new Map(prev);
      for (const tab of tabs) {
        if (!next.has(tab.id)) {
          next.set(tab.id, createTerminalWorkspace());
          changed = true;
        }
      }
      return changed ? next : prev;
    });
  }, [tabs]);

  useEffect(() => {
    setTerminalPanelVisibility((prev) =>
      syncTerminalPanelVisibility(
        prev,
        tabs.map((tab) => tab.id)
      )
    );
  }, [tabs]);

  const handleWorkspaceChange = useCallback(
    (tabId: string, update: WorkspaceUpdate) => {
      setWorkspaceMap((prev) => {
        const next = new Map(prev);
        const current = next.get(tabId) ?? createTerminalWorkspace();
        next.set(
          tabId,
          typeof update === "function" ? update(current) : update
        );
        return next;
      });
    },
    []
  );

  const handleSetTerminalOpen = useCallback((tabId: string, isOpen: boolean) => {
    setTerminalPanelVisibility((prev) => setTerminalPanelOpen(prev, tabId, isOpen));
  }, []);

  // Terminal dispatch — open shell and optionally send a prompt
  const handleSendToAgent = useCallback(
    (agent: string, prompt: string) => {
      if (!activeTab.repoPath) return;

      const resolvedAgent = resolveAgent(agent);
      const tabId = `agent:${resolvedAgent}:${Date.now()}`;
      const agentTab: Tab = {
        id: tabId,
        branch: activeTab.branch,
        repoPath: activeTab.repoPath,
        worktree: activeTab.worktree,
        kind: "agent",
        agent: resolvedAgent,
        hasActiveSession: false,
      };

      setTabs((prev) => [...prev, agentTab]);
      setActiveTabId(tabId);
      handleSetTerminalOpen(tabId, true);
      setPendingAgentLaunch({ tabId, agent: resolvedAgent, prompt });
    },
    [activeTab, handleSetTerminalOpen]
  );

  useEffect(() => {
    if (!pendingAgentLaunch) return;
    if (pendingAgentLaunch.tabId !== activeTabId) return;
    if (!isTerminalOpen) return;

    let cancelled = false;
    let timer = 0;

    const launch = () => {
      if (cancelled) return;
      if (!terminalRef.current) {
        timer = window.setTimeout(launch, 50);
        return;
      }

      terminalRef.current
        .launchSession({
          agent: pendingAgentLaunch.agent,
          prompt: pendingAgentLaunch.prompt,
        })
        .finally(() => {
          setPendingAgentLaunch((current) =>
            current?.tabId === pendingAgentLaunch.tabId ? null : current
          );
        });
    };

    timer = window.setTimeout(launch, 50);
    return () => {
      cancelled = true;
      window.clearTimeout(timer);
    };
  }, [activeTabId, isTerminalOpen, pendingAgentLaunch]);

  // Persist UI state to localStorage
  useEffect(() => {
    localStorage.setItem("entire:terminal-height", String(terminalHeight));
  }, [terminalHeight]);
  useEffect(() => {
    localStorage.setItem("entire:checkpoint-list-width", String(checkpointListWidth));
  }, [checkpointListWidth]);
  useEffect(() => {
    function handleWindowResize() {
      setTerminalHeight((currentHeight) =>
        clampTerminalHeight(currentHeight, window.innerHeight)
      );
    }

    window.addEventListener("resize", handleWindowResize);
    return () => window.removeEventListener("resize", handleWindowResize);
  }, []);

  // Clear selected checkpoint when switching branch tabs
  useEffect(() => {
    setSelectedCheckpoint(null);
    setCheckpointInnerTab("transcript");
  }, [activeTabId]);

  // Keyboard shortcuts
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      const meta = e.metaKey || e.ctrlKey;

      // Cmd+K = focus search
      if (meta && e.key === "k") {
        e.preventDefault();
        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
      }
      // Ctrl+` = toggle terminal
      if (e.ctrlKey && e.key === "`") {
        e.preventDefault();
        handleSetTerminalOpen(activeTabId, !isTerminalOpen);
      }
      // Cmd+W = close active tab
      if (meta && e.key === "w") {
        e.preventDefault();
        handleCloseTab(activeTabId);
      }
      // Cmd+1-9 = switch to tab by index
      if (meta && e.key >= "1" && e.key <= "9") {
        e.preventDefault();
        const idx = parseInt(e.key) - 1;
        if (idx < tabs.length) {
          setActiveTabId(tabs[idx].id);
        }
      }
      // Cmd+[ / Cmd+] = prev/next tab
      if (meta && e.key === "[") {
        e.preventDefault();
        const idx = tabs.findIndex((t) => t.id === activeTabId);
        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
      }
      if (meta && e.key === "]") {
        e.preventDefault();
        const idx = tabs.findIndex((t) => t.id === activeTabId);
        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
      }
      // Escape = deselect checkpoint
      if (e.key === "Escape" && selectedCheckpoint) {
        setSelectedCheckpoint(null);
      }
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [activeTabId, handleSetTerminalOpen, isTerminalOpen, tabs, selectedCheckpoint]);

  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
    const newTab = createBranchTab(branch, repoPath);
    const existing = tabs.find(
      (t) =>
        t.kind === "branch" &&
        t.branch === newTab.branch &&
        t.repoPath === newTab.repoPath
    );
    if (existing) {
      setActiveTabId(existing.id);
    } else {
      setTabs([...tabs, newTab]);
      setActiveTabId(newTab.id);
    }
  }

  function handleWorktreeSelect(wt: WorktreeInfo) {
    const newTab = createWorktreeTab(wt);
    const existing = tabs.find(
      (t) =>
        t.kind === "branch" &&
        t.branch === newTab.branch &&
        t.repoPath === newTab.repoPath
    );
    if (existing) {
      setActiveTabId(existing.id);
    } else {
      setTabs([...tabs, newTab]);
      setActiveTabId(newTab.id);
    }
  }

  function handleCloseTab(tabId: string) {
    if (tabs.length <= 1) return;
    const idx = tabs.findIndex((t) => t.id === tabId);
    const newTabs = tabs.filter((t) => t.id !== tabId);
    setTabs(newTabs);
    if (activeTabId === tabId) {
      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
    }
    const closedWorkspace = workspaceMap.get(tabId);
    for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
      invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
    }
    setWorkspaceMap((prev) => {
      const next = new Map(prev);
      next.delete(tabId);
      return next;
    });
  }

  function handleBranchDeleted(branchName: string, repoPath: string) {
    const tabsToRemove = tabs.filter(
      (tab) =>
        tab.kind === "branch" &&
        tab.worktree === null &&
        tab.branch === branchName &&
        tab.repoPath === repoPath
    );

    if (tabsToRemove.length === 0) {
      return;
    }

    const nextTabs = tabs.filter((tab) => !tabsToRemove.some((candidate) => candidate.id === tab.id));
    setTabs(nextTabs);

    if (tabsToRemove.some((tab) => tab.id === activeTabId) && nextTabs.length > 0) {
      setActiveTabId(nextTabs[0].id);
    }

    setWorkspaceMap((prev) => {
      const next = new Map(prev);
      for (const tab of tabsToRemove) {
        const closedWorkspace = next.get(tab.id);
        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
        }
        next.delete(tab.id);
      }
      return next;
    });
  }

  function handleWorktreeDeleted(worktreePath: string) {
    const cleanup = planWorktreeDeletionCleanup({
      tabs,
      activeTabId,
      worktreePath,
    });

    if (cleanup.removedTabIds.length === 0) {
      return;
    }

    setTabs(cleanup.remainingTabs);

    if (cleanup.nextActiveTabId && cleanup.nextActiveTabId !== activeTabId) {
      setActiveTabId(cleanup.nextActiveTabId);
    }

    setWorkspaceMap((prev) => {
      const next = new Map(prev);
      for (const tabId of cleanup.removedTabIds) {
        const closedWorkspace = next.get(tabId);
        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
        }
        next.delete(tabId);
      }
      return next;
    });
  }

  function handleResizeStart(e: React.MouseEvent) {
    e.preventDefault();
    const startY = e.clientY;
    const startHeight = terminalHeight;

    function onMouseMove(ev: MouseEvent) {
      const delta = startY - ev.clientY;
      setTerminalHeight(
        clampTerminalHeight(startHeight + delta, window.innerHeight)
      );
    }
    function onMouseUp() {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    }
    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
  }

  function handleSidebarResizeStart(e: React.MouseEvent<HTMLDivElement>) {
    e.preventDefault();
    const startX = e.clientX;
    const startWidth = sidebarWidth;

    function onMouseMove(ev: MouseEvent) {
      const delta = ev.clientX - startX;
      setSidebarWidth(clampSidebarWidth(startWidth + delta));
    }

    function onMouseUp() {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    }

    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
  }

  function handleCheckpointListResizeStart(e: React.MouseEvent<HTMLDivElement>) {
    e.preventDefault();
    const startX = e.clientX;
    const startWidth = checkpointListWidth;

    function onMouseMove(ev: MouseEvent) {
      const delta = ev.clientX - startX;
      setCheckpointListWidth(Math.max(200, Math.min(500, startWidth + delta)));
    }

    function onMouseUp() {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    }

    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
  }

  const repoName = activeTab.repoPath
    ? activeTab.repoPath.split("/").pop()
    : "";

  return (
    <div className="flex h-screen flex-col">
      <TitleBar
        title={`Entire — ${repoName ? `${repoName}/` : ""}${activeTab?.branch ?? ""}`}
      />

      <div className="flex flex-1 overflow-hidden">
        {/* Sidebar */}
        <Sidebar
          activeTab={activeTab}
          width={sidebarWidth}
          onBranchSelect={handleBranchSelect}
          onBranchDeleted={handleBranchDeleted}
          onWorktreeDeleted={handleWorktreeDeleted}
          onWorktreeSelect={handleWorktreeSelect}
          onResizeStart={handleSidebarResizeStart}
          onDialogOpen={setIsSidebarDialogOpen}
        />

        {/* Main content */}
        <div className="flex flex-1 flex-col overflow-hidden">
          <TabBar
            tabs={tabsWithSessions}
            activeTabId={activeTabId}
            onSelectTab={setActiveTabId}
            onCloseTab={handleCloseTab}
          />

          <div className="flex flex-1 flex-col overflow-hidden">
            {/* Inner tabs */}
            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
              {(["checkpoints", "diff", "insights", "debug"] as const).map((tab) => (
                <button
                  key={tab}
                  onClick={() => setInnerTab(tab)}
                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
                    innerTab === tab
                      ? "border-accent text-fg"
                      : "border-transparent text-fg-subtle hover:text-fg-muted"
                  }`}
                >
                  {tab === "checkpoints"
                    ? "Checkpoints"
                    : tab === "diff"
                      ? "Diff"
                      : tab === "insights"
                        ? "Insights"
                        : "Debug"}
                </button>
              ))}
            </div>

            {/* Main view */}
            <div className="flex flex-1 overflow-hidden bg-bg">
              {innerTab === "checkpoints" && (
                <>
                  {/* Checkpoint list — always visible when on checkpoints tab */}
                  <div
                    className={`overflow-y-auto ${
                      selectedCheckpoint
                        ? "shrink-0 border-r border-border-subtle"
                        : "flex-1"
                    }`}
                    style={selectedCheckpoint ? { width: checkpointListWidth } : undefined}
                  >
                    <CheckpointList
                      repoPath={activeTab.repoPath}
                      branch={activeTab.branch}
                      onSelectCheckpoint={(cp) => {
                        setSelectedCheckpoint(cp);
                        setCheckpointInnerTab("transcript");
                      }}
                    />
                  </div>

                  {/* Checkpoint list resize handle */}
                  {selectedCheckpoint && (
                    <div
                      onMouseDown={handleCheckpointListResizeStart}
                      className="w-[3px] shrink-0 cursor-col-resize bg-border transition-colors hover:bg-accent"
                    />
                  )}

                  {/* Checkpoint detail panel */}
                  {selectedCheckpoint && (
                    <div className="flex flex-1 flex-col overflow-hidden">
                      {/* Detail header */}
                      <div className="flex items-center gap-3 border-b border-border-subtle px-4 py-2.5">
                        <button
                          onClick={() => setSelectedCheckpoint(null)}
                          className="flex items-center gap-1.5 text-xs text-fg-subtle transition-colors hover:text-fg"
                        >
                          <ArrowLeft size={14} />
                        </button>
                        <GitCommit size={14} className="text-fg-subtle" />
                        <span className="font-mono text-xs text-accent-fg">
                          {selectedCheckpoint.commit_sha
                            ? selectedCheckpoint.commit_sha.slice(0, 7)
                            : selectedCheckpoint.checkpoint_id.slice(0, 7)}
                        </span>
                        <span className="truncate text-xs text-fg-muted">
                          {selectedCheckpoint.commit_message || "Untitled"}
                        </span>
                      </div>

                      {/* Checkpoint sub-tabs */}
                      <div className="flex gap-0 border-b border-border-subtle bg-bg px-4 pt-2">
                        {(["transcript", "diff", "insights", "debug"] as const).map(
                          (tab) => (
                            <button
                              key={tab}
                              onClick={() => setCheckpointInnerTab(tab)}
                              className={`border-b-2 px-3 pb-1.5 text-[11px] font-medium capitalize transition-colors ${
                                checkpointInnerTab === tab
                                  ? "border-accent text-fg"
                                  : "border-transparent text-fg-subtle hover:text-fg-muted"
                              }`}
                            >
                              {tab === "transcript"
                                ? "Transcript"
                                : tab === "diff"
                                  ? "Diff"
                                  : tab === "insights"
                                    ? "Insights"
                                    : "Debug"}
                            </button>
                          )
                        )}
                      </div>

                      {/* Checkpoint detail content */}
                      <div className="flex-1 overflow-y-auto">
                        {checkpointInnerTab === "transcript" && (
                          <TranscriptView
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                          />
                        )}
                        {checkpointInnerTab === "diff" && (
                          <DiffView
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                            onSendToAgent={handleSendToAgent}
                          />
                        )}
                        {checkpointInnerTab === "insights" && (
                          <CheckpointInsightsContainer
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                          />
                        )}
                        {checkpointInnerTab === "debug" && (
                          <CheckpointDebugContainer
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                          />
                        )}
                      </div>
                    </div>
                  )}
                </>
              )}
              {innerTab === "diff" && (
                <div className="flex flex-1 overflow-hidden">
                  <BranchDiffView
                    repoPath={activeTab.repoPath}
                    branch={activeTab.branch}
                    onSendToAgent={handleSendToAgent}
                  />
                </div>
              )}
              {innerTab === "insights" && (
                <div className="flex flex-1 overflow-y-auto">
                  <BranchInsightsContainer
                    repoPath={activeTab.repoPath}
                    branch={activeTab.branch}
                  />
                </div>
              )}
              {innerTab === "debug" && (
                <div className="flex flex-1 overflow-y-auto">
                  <BranchDebugContainer
                    repoPath={activeTab.repoPath}
                    branch={activeTab.branch}
                  />
                </div>
              )}
            </div>

            {/* Resize handle */}
            {isTerminalOpen && (
              <div
                onMouseDown={handleResizeStart}
                className="h-[3px] shrink-0 cursor-row-resize bg-border transition-colors hover:bg-accent"
              />
            )}

            {/* Terminal panel */}
            {isTerminalOpen && (
              <TerminalPanel
                ref={terminalRef}
                height={terminalHeight}
                tab={activeTab}
                workspace={activeWorkspace}
                onWorkspaceChange={(update) =>
                  handleWorkspaceChange(activeTab.id, update)
                }
                onToggle={() => handleSetTerminalOpen(activeTab.id, false)}
                dialogOpen={isSidebarDialogOpen}
              />
            )}
          </div>
        </div>
      </div>

      {!isTerminalOpen && (
        <button
          onClick={() => handleSetTerminalOpen(activeTab.id, true)}
          className="flex h-7 shrink-0 items-center justify-center border-t border-border bg-bg-raised text-[11px] text-fg-subtle hover:text-fg-muted"
        >
          ▲ Terminal (⌃`)
        </button>
      )}
    </div>
  );
}

